+    [Test]
+    [HandlerFunctions('ProdOrderPickSelectionPageHandler')]
+    [Scope('OnPrem')]
+    procedure CreatePickFromPickWorksheetWithBinMandatoryAndReservedProdOrderComponents()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        Location: Record Location;
+        Bin: Record Bin;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: array[2] of Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        WhseWorksheetName: Record "Whse. Worksheet Name";
+        WhseWorksheetLine: Record "Whse. Worksheet Line";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseEmployee: Record "Warehouse Employee";
+        GetSourceDocOutbound: Codeunit "Get Source Doc. Outbound";
+        TotalComponentQty: Decimal;
+        i: Integer;
+    begin
+        // [FEATURE] [Pick Worksheet] [Reservation] [Production Order] [Bin Mandatory]
+        // [SCENARIO] Create pick from pick worksheet should work when location has Bin Mandatory and 
+        // Prod. Consump. Whse. Handling is set to "Warehouse Pick (mandatory)" with reserved components.
+        Initialize();
+
+        // [GIVEN] Create a location with Bin Mandatory = TRUE and "Prod. Consump. Whse. Handling" = "Warehouse Pick (mandatory)"
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Bin Mandatory", true);
+        Location."Prod. Consump. Whse. Handling" := Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)";
+        Location.Modify(true);
+        LibraryWarehouse.CreateBin(Bin, Location.Code, LibraryUtility.GenerateGUID(), '', '');
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Create a component item and post 3 PCS to inventory
+        LibraryInventory.CreateItem(ComponentItem);
+        TotalComponentQty := 3;
+        CreateAndPostItemJournalLine(ComponentItem."No.", TotalComponentQty, Location.Code, Bin.Code);
+
+        // [GIVEN] Create a parent item with a production BOM containing the component
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, ComponentItem."No.", 1);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create first Released Production Order for 2 PCS and refresh
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder[1], ProductionOrder[1].Status::Released, ProductionOrder[1]."Source Type"::Item, ParentItem."No.", 2);
+        ProductionOrder[1].Validate("Location Code", Location.Code);
+        ProductionOrder[1].Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder[1], false, true, true, true, false);
+
+        // [GIVEN] Reserve component from inventory for first production order
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder[1]."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+        ProdOrderComponent.Validate("Bin Code", Bin.Code);
+        ProdOrderComponent.Modify(true);
+        ProdOrderComponent.AutoReserve();
+
+        // [GIVEN] Create second Released Production Order for 1 PCS and refresh
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder[2], ProductionOrder[2].Status::Released, ProductionOrder[2]."Source Type"::Item, ParentItem."No.", 1);
+        ProductionOrder[2].Validate("Location Code", Location.Code);
+        ProductionOrder[2].Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder[2], false, true, true, true, false);
+
+        // [GIVEN] Reserve component from inventory for second production order
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder[2]."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+        ProdOrderComponent.Validate("Bin Code", Bin.Code);
+        ProdOrderComponent.Modify(true);
+        ProdOrderComponent.AutoReserve();
+
+        // [GIVEN] Get both production orders into pick worksheet
+        WhseWorksheetLine.DeleteAll();
+        LibraryWarehouse.SelectWhseWorksheetTemplate(WhseWorksheetName, WhseWorksheetName."Template Type"::Pick);
+        LibraryWarehouse.CreateWhseWorksheetName(WhseWorksheetName, WhseWorksheetName."Worksheet Template Name", Location.Code);
+        for i := 1 to 2 do begin
+            LibraryVariableStorage.Enqueue(ProductionOrder[i]."No.");
+            LibraryVariableStorage.Enqueue(Location.Code);
+            GetSourceDocOutbound.GetSingleWhsePickDoc(
+              WhseWorksheetName."Worksheet Template Name", WhseWorksheetName.Name, Location.Code);
+        end;
+
+        // [WHEN] Create Pick from pick worksheet for both lines
+        WhseWorksheetLine.SetRange("Worksheet Template Name", WhseWorksheetName."Worksheet Template Name");
+        WhseWorksheetLine.SetRange(Name, WhseWorksheetName.Name);
+        WhseWorksheetLine.SetRange("Location Code", Location.Code);
+        WhseWorksheetLine.FindFirst();
+        LibraryWarehouse.CreatePickFromPickWorksheet(
+          WhseWorksheetLine, WhseWorksheetLine."Line No.", WhseWorksheetName."Worksheet Template Name", WhseWorksheetName.Name,
+          Location.Code, '', 0, 0, "Whse. Activity Sorting Method"::None, false, false, false, false, false, false, false);
+
+        // [THEN] Pick lines are created successfully (no availability error)
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("Location Code", Location.Code);
+        WarehouseActivityLine.SetRange("Item No.", ComponentItem."No.");
+        Assert.IsFalse(WarehouseActivityLine.IsEmpty(), 'Expected pick lines to be created');
+    end;
+
