+    [Test]
+    procedure VariantCodeNotPresetOnNewSalesPriceListLine()
+    var
+        Item: Record Item;
+        ItemVariant: array[2] of Record "Item Variant";
+        PriceListHeader: Record "Price List Header";
+        SalesPriceList: TestPage "Sales Price List";
+    begin
+        // [SCENARIO] When creating a new price list line for variant items, the variant code should not be preset from the previous line
+        Initialize(true);
+
+        // [GIVEN] Item 'I' with Variants 'V1' and 'V2'
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant[1], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[2], Item."No.");
+
+        // [GIVEN] Sales Price List
+        LibraryPriceCalculation.CreatePriceHeader(PriceListHeader, "Price Type"::Sale, "Price Source Type"::"All Customers", '');
+
+        // [GIVEN] Open Sales Price List page
+        SalesPriceList.OpenEdit();
+        SalesPriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+
+        // [GIVEN] Add a line with Item 'I' and Variant 'V1'
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Asset Type".SetValue("Price Asset Type"::Item);
+        SalesPriceList.Lines."Asset No.".SetValue(Item."No.");
+        SalesPriceList.Lines."Variant Code".SetValue(ItemVariant[1].Code);
+        SalesPriceList.Lines."Unit Price".SetValue(100);
+
+        // [WHEN] Add a second line for the same Item
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Asset Type".SetValue("Price Asset Type"::Item);
+        SalesPriceList.Lines."Asset No.".SetValue(Item."No.");
+
+        // [THEN] Variant Code should be blank, not preset from previous line
+        SalesPriceList.Lines."Variant Code".AssertEquals('');
+    end;
+
