@@ -0,0 +1,79 @@
+codeunit 148181 "Sustainability Setup Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit "Assert";
+        LibrarySustainability: Codeunit "Library - Sustainability";
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    procedure VerifyEnablingValueChainTrackingEnablesEmissionFields()
+    var
+        SustainabilitySetup: Record "Sustainability Setup";
+    begin
+        // [SCENARIO] Verify that enabling "Enable Value Chain Tracking" automatically enables the emission fields
+        // Bug: W1 2025 - Bug Bash IV [Sustainability] Value Chain Tracking Enablement
+        // When "Enable Value Chain Tracking" is enabled, the following fields should also be enabled:
+        // - Use Emissions In Purchase Documents
+        // - Item Emissions
+        // - Resource Emissions
+        // - Work/Machine Center Emissions
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] Get Sustainability Setup with all procurement fields disabled
+        SustainabilitySetup.Get();
+        SustainabilitySetup."Use Emissions In Purch. Doc." := false;
+        SustainabilitySetup."Item Emissions" := false;
+        SustainabilitySetup."Resource Emissions" := false;
+        SustainabilitySetup."Work/Machine Center Emissions" := false;
+        SustainabilitySetup."Enable Value Chain Tracking" := false;
+        SustainabilitySetup.Modify();
+
+        // [WHEN] Enable Value Chain Tracking is set to true
+        SustainabilitySetup.Get();
+        SustainabilitySetup.Validate("Enable Value Chain Tracking", true);
+
+        // [THEN] The following fields should be automatically enabled
+        Assert.IsTrue(SustainabilitySetup."Use Emissions In Purch. Doc.", 'Use Emissions In Purch. Doc. should be enabled');
+        Assert.IsTrue(SustainabilitySetup."Item Emissions", 'Item Emissions should be enabled');
+        Assert.IsTrue(SustainabilitySetup."Resource Emissions", 'Resource Emissions should be enabled');
+        Assert.IsTrue(SustainabilitySetup."Work/Machine Center Emissions", 'Work/Machine Center Emissions should be enabled');
+    end;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    procedure VerifyEnablingValueChainTrackingKeepsPreviouslyEnabledEmissionFields()
+    var
+        SustainabilitySetup: Record "Sustainability Setup";
+    begin
+        // [SCENARIO] Verify that enabling "Enable Value Chain Tracking" keeps previously enabled emission fields
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] Get Sustainability Setup with some emission fields already enabled
+        SustainabilitySetup.Get();
+        SustainabilitySetup.Validate("Use Emissions In Purch. Doc.", true);
+        SustainabilitySetup.Validate("Item Emissions", true);
+        SustainabilitySetup."Resource Emissions" := false;
+        SustainabilitySetup."Work/Machine Center Emissions" := false;
+        SustainabilitySetup."Enable Value Chain Tracking" := false;
+        SustainabilitySetup.Modify();
+
+        // [WHEN] Enable Value Chain Tracking is set to true
+        SustainabilitySetup.Get();
+        SustainabilitySetup.Validate("Enable Value Chain Tracking", true);
+
+        // [THEN] All emission fields should be enabled (previously enabled ones stay enabled, disabled ones become enabled)
+        Assert.IsTrue(SustainabilitySetup."Use Emissions In Purch. Doc.", 'Use Emissions In Purch. Doc. should remain enabled');
+        Assert.IsTrue(SustainabilitySetup."Item Emissions", 'Item Emissions should remain enabled');
+        Assert.IsTrue(SustainabilitySetup."Resource Emissions", 'Resource Emissions should be enabled');
+        Assert.IsTrue(SustainabilitySetup."Work/Machine Center Emissions", 'Work/Machine Center Emissions should be enabled');
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+}

