     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure JobJnlLineWithNonDeductNormalVATFromGenJnlLineWithFCYJob()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJnlLine: Record "Gen. Journal Line";
+        JobJnlLine: Record "Job Journal Line";
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        Customer: Record Customer;
+        JobTransferLine: Codeunit "Job Transfer Line";
+        DeductiblePercent: Decimal;
+        ExpectedUnitCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+        CurrencyFactor: Decimal;
+    begin
+        // [FEATURE] [Normal VAT] [UT] [FCY]
+        // [SCENARIO] Job journal line built from the general journal line (LCY) includes non deductible VAT in "Unit Cost" 
+        // correctly converted when the job has a foreign currency
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+        // [GIVEN] VAT Posting Setup, where "Tax Calculation Type"::"Normal VAT", 'Deductible %' is '60'
+        DeductiblePercent := LibraryRandom.RandInt(90);
+        CreateNonDeductibleVATPostingSetup(VATPostingSetup, "Tax Calculation Type"::"Normal VAT", '', DeductiblePercent);
+        // [GIVEN] Job with foreign currency (EUR)
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", LibraryERM.CreateCurrencyWithRandomExchRates());
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+        // [GIVEN] General journal line in LCY where line contains Amount = 100, "Job No." = 'J', "Job Task No." = 'JT', "Job Line Type" = 'Billable'
+        LibraryJob.CreateJobGLJournalLine(GenJnlLine."Job Line Type"::Billable, JobTask, GenJnlLine);
+        GenJnlLine.Validate("Gen. Posting Type", GenJnlLine."Gen. Posting Type"::Purchase);
+        GenJnlLine.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GenJnlLine.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GenJnlLine.Modify(true);
+        // [GIVEN] Currency Factor from LCY to Job Currency
+        CurrencyFactor := GenJnlLine.GetGenJnlLineToJobCurrencyFactor();
+
+        // [WHEN] Run FromGenJnlLineToJnlLine
+        JobTransferLine.FromGenJnlLineToJnlLine(GenJnlLine, JobJnlLine);
+
+        // [THEN] JobJnlLine contains "Unit Cost (LCY)" with Non-Deductible VAT amount correctly converted using currency factor
+        ExpectedTotalCostLCY := Round(GenJnlLine."Non-Deductible VAT Amount" * CurrencyFactor);
+        ExpectedUnitCostLCY := Round(ExpectedTotalCostLCY / GenJnlLine."Job Quantity");
+        Assert.AreEqual(
+            Round(JobJnlLine."Unit Cost (LCY)"),
+            Round((GenJnlLine."VAT Base Amount (LCY)" + ExpectedUnitCostLCY * GenJnlLine."Job Quantity") / GenJnlLine."Job Quantity"),
+            'Unit Cost (LCY) with Non-Deductible VAT amount is not correctly converted for Job with FCY');
+        // [THEN] JobJnlLine contains "Total Cost (LCY)" with Non-Deductible VAT amount correctly converted using currency factor
+        Assert.AreEqual(
+            Round(JobJnlLine."Total Cost (LCY)"),
+            Round(GenJnlLine."VAT Base Amount (LCY)" + ExpectedTotalCostLCY),
+            'Total Cost (LCY) with Non-Deductible VAT amount is not correctly converted for Job with FCY');
+    end;
+
