diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrdersV.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrdersV.Codeunit.al
index ac6b3958..f2242110 100644
--- a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrdersV.Codeunit.al
+++ b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProductionOrdersV.Codeunit.al
@@ -1062,6 +1062,77 @@ codeunit 137084 "SCM Production Orders V"
         LibraryVariableStorage.Clear();
     end;

+    [Test]
+    procedure VerifyQtyPerInComponentWhenItemUOMHasRoundingPrecisionOfOne()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodItem: Record Item;
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        QtyPerInBOM: Decimal;
+    begin
+        // [SCENARIO 123456] When a component's Item UOM has 'Qty. Rounding Precision' of 1,
+        // and a Finished Good consumes a fractional quantity per unit,
+        // the Prod. Order created should have correct 'Quantity Per' and 'Expected Quantity'.
+        // Without the fix, these values would incorrectly be 0 due to rounding.
+        Initialize();
+
+        // [GIVEN] A component item with Replenishment System = Purchase, Rounding Precision = 0.01
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] The component Item UOM has 'Qty. Rounding Precision' = 1 (integer rounding)
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] A finished good item with Replenishment System = Prod. Order
+        LibraryInventory.CreateItem(FinishedGoodItem);
+        FinishedGoodItem.Validate("Replenishment System", FinishedGoodItem."Replenishment System"::"Prod. Order");
+        FinishedGoodItem.Validate("Rounding Precision", 1);
+        FinishedGoodItem.Modify(true);
+
+        // [GIVEN] A Production BOM that consumes the component with Quantity Per = 0.09 (fractional)
+        QtyPerInBOM := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FinishedGoodItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPerInBOM);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Assign the Production BOM to the finished good item
+        FinishedGoodItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodItem.Modify(true);
+
+        // [WHEN] Create and refresh a Released Production Order for 1 unit of the finished good item
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, FinishedGoodItem."No.", 1);
+
+        // [THEN] The Prod. Order Component should have 'Quantity Per' equal to the BOM value (0.09), not 0
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        // Verify that 'Quantity Per' is the expected value from the BOM (0.09), not rounded to 0
+        Assert.AreEqual(
+            QtyPerInBOM,
+            ProdOrderComponent."Quantity per",
+            StrSubstNo(ValueMustBeEqualErr, ProdOrderComponent.FieldCaption("Quantity per"), QtyPerInBOM, ProdOrderComponent.TableCaption()));
+
+        // Verify that 'Expected Quantity' is also correct (0.09 for 1 unit of finished good)
+        Assert.AreEqual(
+            QtyPerInBOM,
+            ProdOrderComponent."Expected Quantity",
+            StrSubstNo(ValueMustBeEqualErr, ProdOrderComponent.FieldCaption("Expected Quantity"), QtyPerInBOM, ProdOrderComponent.TableCaption()));
+    end;
+
     local procedure Initialize()
     begin
         LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Production Orders V");

