+
+        // [WHEN] Navigating from Outbox for this Credit Memo transaction
+        PostedSalesCreditMemo.Trap();
+        ICOutboxTransactions.GoToDocument.Invoke();
+
+        // [THEN] It should open the Posted Sales Credit Memo
+        SalesCrMemoHeader.Get(PostedDocNo);
+        PostedSalesCreditMemo."No.".AssertEquals(PostedDocNo);
+
+        // Cleanup
+        CleanupIC();
+    end;
+
+    local procedure Initialize()
+    var
+        ICSetup: Record "IC Setup";
+    begin
+        // Set up IC Partner Code in IC Setup if not already set
+        if not ICSetup.Get() then begin
+            ICSetup.Init();
+            ICSetup.Insert();
+        end;
+        if ICSetup."IC Partner Code" = '' then begin
+            ICSetup.Validate("IC Partner Code", CopyStr(LibraryUtility.GenerateRandomCode(ICSetup.FieldNo("IC Partner Code"), Database::"IC Setup"), 1, 20));
+            ICSetup.Modify(true);
+        end;
+    end;
+
+    local procedure CreateICPartnerCode(): Code[20]
+    var
+        ICPartner: Record "IC Partner";
+    begin
+        ICPartner.Init();
+        ICPartner.Validate(Code, LibraryUtility.GenerateRandomCode(ICPartner.FieldNo(Code), Database::"IC Partner"));
+        ICPartner.Validate(Name, ICPartner.Code);
+        ICPartner.Insert(true);
+        exit(ICPartner.Code);
+    end;
+
+    local procedure CreateCustomerWithICPartner(var Customer: Record Customer; ICPartnerCode: Code[20])
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("IC Partner Code", ICPartnerCode);
+        Customer.Modify(true);
+    end;
+
+    local procedure CleanupIC()
+    var
+        ICOutboxTransaction: Record "IC Outbox Transaction";
+        HandledICOutboxTrans: Record "Handled IC Outbox Trans.";
+        SalesHeader: Record "Sales Header";
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+    begin
+        ICOutboxTransaction.DeleteAll();
+        HandledICOutboxTrans.DeleteAll();
+    end;
+}

