+    [Test]
+    procedure AvailWarningNotConsideringFutureDemandDueDates()
+    var
+        AsmItem: Record Item;
+        CompItem: Record Item;
+        BOMComponent: Record "BOM Component";
+        ItemJournalLine: Record "Item Journal Line";
+        AssemblyHeader: array[2] of Record "Assembly Header";
+        AssemblyLine: array[2] of Record "Assembly Line";
+        FirstOrderDueDate: Date;
+        SecondOrderDueDate: Date;
+    begin
+        // [FEATURE] [Availability] [Avail. Warning]
+        // [SCENARIO] Avail. Warning on Assembly Orders should consider Due Dates, not all future demand.
+        // Bug repro: When a second assembly order is created with a later due date, the first assembly order
+        // incorrectly shows Avail. Warning = Yes even though inventory is sufficient for its due date.
+        Initialize();
+
+        // [GIVEN] Assembly item with a component that requires 2 qty per assembled item.
+        LibraryInventory.CreateItem(AsmItem);
+        AsmItem.Validate("Replenishment System", AsmItem."Replenishment System"::Assembly);
+        AsmItem.Modify(true);
+
+        LibraryInventory.CreateItem(CompItem);
+        LibraryInventory.CreateBOMComponent(
+          BOMComponent, AsmItem."No.", BOMComponent.Type::Item, CompItem."No.", 2, CompItem."Base Unit of Measure");
+
+        // [GIVEN] Post 2 pcs of the component to inventory - exactly enough for 1 assembly.
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, CompItem."No.", '', '', 2);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] First assembly order for 1 pc with due date = WorkDate + 5 (requires 2 components).
+        FirstOrderDueDate := WorkDate() + 5;
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[1], FirstOrderDueDate, AsmItem."No.", '', 1, '');
+        FindAssemblyLine(AssemblyLine[1], AssemblyHeader[1], CompItem."No.");
+
+        // [GIVEN] Verify first order has no availability warning (inventory = 2, demand = 2).
+        AssemblyLine[1].UpdateAvailWarning();
+        Assert.IsFalse(AssemblyLine[1]."Avail. Warning", 'First assembly order should NOT have availability warning before creating second order.');
+
+        // [GIVEN] Second assembly order for 3 pcs with later due date = WorkDate + 10 (requires 6 components).
+        SecondOrderDueDate := WorkDate() + 10;
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[2], SecondOrderDueDate, AsmItem."No.", '', 3, '');
+        FindAssemblyLine(AssemblyLine[2], AssemblyHeader[2], CompItem."No.");
+
+        // [WHEN] We check the Avail. Warning on the first assembly order again.
+        AssemblyLine[1].Get(AssemblyLine[1]."Document Type", AssemblyLine[1]."Document No.", AssemblyLine[1]."Line No.");
+        AssemblyLine[1].UpdateAvailWarning();
+
+        // [THEN] First assembly order should still NOT have availability warning.
+        // The second order's demand (due on a later date) should not affect the first order's availability.
+        Assert.IsFalse(AssemblyLine[1]."Avail. Warning", 'First assembly order should NOT have availability warning - inventory is sufficient for its due date.');
+
+        // [THEN] Second assembly order SHOULD have availability warning (needs 6, only 0 available after first order).
+        AssemblyLine[2].UpdateAvailWarning();
+        Assert.IsTrue(AssemblyLine[2]."Avail. Warning", 'Second assembly order SHOULD have availability warning - insufficient inventory.');
+    end;
+
