diff --git a/App/Layers/W1/Tests/Job/RecurringJobJournalTest.Codeunit.al b/App/Layers/W1/Tests/Job/RecurringJobJournalTest.Codeunit.al
new file mode 100644
index 00000000..16868511
--- /dev/null
+++ b/App/Layers/W1/Tests/Job/RecurringJobJournalTest.Codeunit.al
@@ -0,0 +1,277 @@
+codeunit 136399 "Recurring Job Journal Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Job] [Recurring Job Journal]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryResource: Codeunit "Library - Resource";
+        LibrarySales: Codeunit "Library - Sales";
+        Initialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJournalVariableMethodPreservesUnitCostAndPrice()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        Resource: Record Resource;
+        ExpectedUnitCost: Decimal;
+        ExpectedUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal]
+        // [SCENARIO] When posting a recurring job journal with Variable method, Unit Cost and Unit Price should be preserved after posting
+
+        // [GIVEN] A recurring job journal template and batch
+        Initialize();
+        CreateRecurringJobJournalTemplateAndBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A job with a job task
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] A resource with defined Unit Cost and Unit Price
+        Resource.Get(LibraryResource.CreateResourceNo());
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A recurring job journal line with Variable method
+        CreateRecurringJobJournalLine(
+            JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name,
+            JobTask, Resource."No.", JobJournalLine."Recurring Method"::Variable);
+
+        ExpectedUnitCost := JobJournalLine."Unit Cost";
+        ExpectedUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] Posting the recurring job journal
+        CODEUNIT.Run(CODEUNIT::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The job journal line should have Unit Cost and Unit Price preserved after posting
+        JobJournalLine.Reset();
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        Assert.AreEqual(ExpectedUnitCost, JobJournalLine."Unit Cost",
+            'Unit Cost should be preserved after posting recurring journal with Variable method');
+        Assert.AreEqual(ExpectedUnitPrice, JobJournalLine."Unit Price",
+            'Unit Price should be preserved after posting recurring journal with Variable method');
+
+        // [THEN] Quantity should be reset to 0 for Variable method
+        Assert.AreEqual(0, JobJournalLine.Quantity,
+            'Quantity should be reset to 0 for Variable recurring method');
+
+        // Cleanup
+        JobJournalTemplate.Delete(true);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJournalVariableMethodRevalidatingQuantityUsesPreservedUnitCost()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        Resource: Record Resource;
+        ExpectedUnitCost: Decimal;
+        ExpectedUnitPrice: Decimal;
+        NewQuantity: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal]
+        // [SCENARIO] When re-adding quantity to a posted recurring job journal line with Variable method,
+        // the preserved Unit Cost and Unit Price should be used to calculate total amounts
+
+        // [GIVEN] A recurring job journal template and batch
+        Initialize();
+        CreateRecurringJobJournalTemplateAndBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A job with a job task
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] A resource with defined Unit Cost and Unit Price
+        Resource.Get(LibraryResource.CreateResourceNo());
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A recurring job journal line with Variable method
+        CreateRecurringJobJournalLine(
+            JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name,
+            JobTask, Resource."No.", JobJournalLine."Recurring Method"::Variable);
+
+        ExpectedUnitCost := JobJournalLine."Unit Cost";
+        ExpectedUnitPrice := JobJournalLine."Unit Price";
+
+        // [GIVEN] The recurring job journal is posted
+        CODEUNIT.Run(CODEUNIT::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [WHEN] Adding a new quantity to the recurring journal line
+        JobJournalLine.Reset();
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        NewQuantity := LibraryRandom.RandDecInRange(1, 10, 2);
+        JobJournalLine.Validate(Quantity, NewQuantity);
+        JobJournalLine.Modify(true);
+
+        // [THEN] The Total Cost should be calculated using the preserved Unit Cost
+        Assert.AreEqual(ExpectedUnitCost, JobJournalLine."Unit Cost",
+            'Unit Cost should remain preserved after adding quantity');
+        Assert.AreEqual(ExpectedUnitPrice, JobJournalLine."Unit Price",
+            'Unit Price should remain preserved after adding quantity');
+
+        // [THEN] Total Cost should be correctly calculated
+        Assert.AreNearlyEqual(ExpectedUnitCost * NewQuantity, JobJournalLine."Total Cost", 0.01,
+            'Total Cost should be calculated using preserved Unit Cost');
+        Assert.AreNearlyEqual(ExpectedUnitPrice * NewQuantity, JobJournalLine."Line Amount", 0.01,
+            'Line Amount should be calculated using preserved Unit Price');
+
+        // Cleanup
+        JobJournalTemplate.Delete(true);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJournalFixedMethodResetsAllAmounts()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        Resource: Record Resource;
+        OriginalQuantity: Decimal;
+        OriginalUnitCost: Decimal;
+        OriginalUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal]
+        // [SCENARIO] When posting a recurring job journal with Fixed method, all values including Unit Cost and Unit Price should be preserved
+
+        // [GIVEN] A recurring job journal template and batch
+        Initialize();
+        CreateRecurringJobJournalTemplateAndBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A job with a job task
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] A resource with defined Unit Cost and Unit Price
+        Resource.Get(LibraryResource.CreateResourceNo());
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A recurring job journal line with Fixed method
+        CreateRecurringJobJournalLine(
+            JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name,
+            JobTask, Resource."No.", JobJournalLine."Recurring Method"::Fixed);
+
+        OriginalQuantity := JobJournalLine.Quantity;
+        OriginalUnitCost := JobJournalLine."Unit Cost";
+        OriginalUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] Posting the recurring job journal
+        CODEUNIT.Run(CODEUNIT::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The job journal line should have all amounts preserved (Fixed method keeps everything)
+        JobJournalLine.Reset();
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        Assert.AreEqual(OriginalQuantity, JobJournalLine.Quantity,
+            'Quantity should be preserved for Fixed recurring method');
+        Assert.AreEqual(OriginalUnitCost, JobJournalLine."Unit Cost",
+            'Unit Cost should be preserved for Fixed recurring method');
+        Assert.AreEqual(OriginalUnitPrice, JobJournalLine."Unit Price",
+            'Unit Price should be preserved for Fixed recurring method');
+
+        // Cleanup
+        JobJournalTemplate.Delete(true);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Recurring Job Journal Test");
+
+        if Initialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Recurring Job Journal Test");
+
+        LibrarySales.SetCreditWarningsToNoWarnings();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibraryERMCountryData.UpdateLocalData();
+        LibrarySales.SetExtDocNo(false);
+
+        Initialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Recurring Job Journal Test");
+    end;
+
+    local procedure CreateRecurringJobJournalTemplateAndBatch(var JobJournalTemplate: Record "Job Journal Template"; var JobJournalBatch: Record "Job Journal Batch")
+    var
+        SourceCodeSetup: Record "Source Code Setup";
+    begin
+        SourceCodeSetup.Get();
+
+        JobJournalTemplate.Init();
+        JobJournalTemplate.Name := CopyStr(LibraryRandom.RandText(10), 1, MaxStrLen(JobJournalTemplate.Name));
+        JobJournalTemplate.Recurring := true;
+        JobJournalTemplate."Source Code" := SourceCodeSetup."Job Journal";
+        JobJournalTemplate.Insert(true);
+
+        JobJournalBatch.Init();
+        JobJournalBatch."Journal Template Name" := JobJournalTemplate.Name;
+        JobJournalBatch.Name := CopyStr(LibraryRandom.RandText(10), 1, MaxStrLen(JobJournalBatch.Name));
+        JobJournalBatch.Insert(true);
+    end;
+
+    local procedure CreateRecurringJobJournalLine(var JobJournalLine: Record "Job Journal Line"; TemplateName: Code[10]; BatchName: Code[10]; JobTask: Record "Job Task"; ResourceNo: Code[20]; RecurringMethod: Option)
+    var
+        RecurringFrequency: DateFormula;
+    begin
+        Evaluate(RecurringFrequency, '<1M>');
+
+        JobJournalLine.Init();
+        JobJournalLine."Journal Template Name" := TemplateName;
+        JobJournalLine."Journal Batch Name" := BatchName;
+        JobJournalLine."Line No." := 10000;
+        JobJournalLine.Insert(true);
+
+        JobJournalLine.Validate("Posting Date", WorkDate());
+        JobJournalLine.Validate("Document No.", CopyStr(LibraryRandom.RandText(10), 1, MaxStrLen(JobJournalLine."Document No.")));
+        JobJournalLine.Validate("Job No.", JobTask."Job No.");
+        JobJournalLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobJournalLine.Validate("Line Type", JobJournalLine."Line Type"::Billable);
+        JobJournalLine.Validate(Type, JobJournalLine.Type::Resource);
+        JobJournalLine.Validate("No.", ResourceNo);
+        JobJournalLine.Validate(Quantity, LibraryRandom.RandDecInRange(1, 10, 2));
+        JobJournalLine.Validate("Recurring Method", RecurringMethod);
+        JobJournalLine.Validate("Recurring Frequency", RecurringFrequency);
+        JobJournalLine.Modify(true);
+    end;
+}

