diff --git a/App/Layers/W1/Tests/Misc/IssuedReminderEmailTest.Codeunit.al b/App/Layers/W1/Tests/Misc/IssuedReminderEmailTest.Codeunit.al
new file mode 100644
index 00000000..ca0f9ac9
--- /dev/null
+++ b/App/Layers/W1/Tests/Misc/IssuedReminderEmailTest.Codeunit.al
@@ -0,0 +1,66 @@
+codeunit 134423 "Issued Reminder Email Test"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Report Selection] [Issued Reminder] [Email]
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderHeaderHasCustomerNoFieldNotSellToCustomerNo()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        RecRef: RecordRef;
+        FieldRef: FieldRef;
+        DataTypeManagement: Codeunit "Data Type Management";
+    begin
+        // [SCENARIO] Issued Reminder Header uses 'Customer No.' field, not 'Sell-to Customer No.'
+        // The email sending code in ReportSelections.SendEmailDirectly uses 'Sell-to Customer No.'
+        // for customer account documents by default. Without the fix, this would cause the
+        // customer lookup to fail for Issued Reminder Header because that field doesn't exist.
+        // The fix adds special handling to use 'Customer No.' for Issued Reminder Header,
+        // ensuring emails appear in the customer's sent email history.
+
+        // [GIVEN] Create a customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Create an Issued Reminder Header with the customer
+        CreateIssuedReminderHeader(IssuedReminderHeader, Customer."No.");
+
+        // [GIVEN] Get RecordRef for the Issued Reminder Header
+        RecRef.GetTable(IssuedReminderHeader);
+
+        // [WHEN] Looking for the customer field on Issued Reminder Header
+        // [THEN] The field 'Customer No.' should exist and have the correct value
+        Assert.IsTrue(DataTypeManagement.FindfieldByName(RecRef, FieldRef, 'Customer No.'),
+            'Field ''Customer No.'' must exist on Issued Reminder Header for email linking to work.');
+        Assert.AreEqual(Customer."No.", Format(FieldRef.Value()),
+            'Customer No. field should contain the correct customer number');
+
+        // [THEN] The field 'Sell-to Customer No.' should NOT exist on Issued Reminder Header
+        // This is why the fix is necessary - the default 'Sell-to Customer No.' doesn't work here
+        Assert.IsFalse(DataTypeManagement.FindfieldByName(RecRef, FieldRef, 'Sell-to Customer No.'),
+            'Field ''Sell-to Customer No.'' does NOT exist on Issued Reminder Header. ' +
+            'Without the fix, using ''Sell-to Customer No.'' would cause customer lookup to fail, ' +
+            'and issued reminder emails would not appear in customer''s sent email history.');
+    end;
+
+    local procedure CreateIssuedReminderHeader(var IssuedReminderHeader: Record "Issued Reminder Header"; CustomerNo: Code[20])
+    begin
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader."No." := LibraryUtility.GenerateRandomCode(
+            IssuedReminderHeader.FieldNo("No."), Database::"Issued Reminder Header");
+        IssuedReminderHeader."Customer No." := CustomerNo;
+        IssuedReminderHeader."Due Date" := WorkDate();
+        IssuedReminderHeader.Insert(false);
+    end;
+}

