+codeunit 137802 "SCM - Planning Worksheet Batch"
+{
+    // [FEATURE] [Planning Worksheet] [Batch]
+    // Tests for Planning Worksheet batch handling, ensuring the correct batch is opened
+    // when navigating from Item Availability by Event to Planning Worksheet.
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('PlanningWorksheetModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure OpenJnlUsesWorksheetTemplateNameFromRecordWhenSetDirectly()
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        RequisitionWkshName1: Record "Requisition Wksh. Name";
+        RequisitionWkshName2: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        Item: Record Item;
+        CalcItemAvailability: Codeunit "Calc. Item Availability";
+        RecRef: RecordRef;
+    begin
+        // [SCENARIO] When opening Planning Worksheet from Item Availability by Event via ShowDocument,
+        // the correct batch (where the requisition line exists) should be opened, not the last used batch.
+        // This test verifies the fix for the bug where the wrong Planning Worksheet batch was opened
+        // when viewing document from Item Availability by Event.
+        Initialize();
+
+        // [GIVEN] A Planning Worksheet template exists
+        CreatePlanningReqWkshTemplate(ReqWkshTemplate);
+
+        // [GIVEN] Two Planning Worksheet batches: "BATCH1" and "BATCH2"
+        CreateRequisitionWkshName(RequisitionWkshName1, ReqWkshTemplate.Name);
+        CreateRequisitionWkshName(RequisitionWkshName2, ReqWkshTemplate.Name);
+
+        // [GIVEN] An item with a requisition line in "BATCH1"
+        LibraryInventory.CreateItem(Item);
+        CreateRequisitionLine(RequisitionLine, ReqWkshTemplate.Name, RequisitionWkshName1.Name, Item."No.");
+
+        // [GIVEN] Store expected batch name for verification in page handler
+        LibraryVariableStorage.Enqueue(RequisitionWkshName1.Name);
+
+        // [WHEN] ShowDocument is called for the requisition line (simulating navigation from Item Availability by Event)
+        // The requisition line has both Worksheet Template Name and Journal Batch Name set directly
+        RecRef.GetTable(RequisitionLine);
+        CalcItemAvailability.ShowDocument(RecRef.RecordId);
+
+        // [THEN] The Planning Worksheet page opens with the correct batch "BATCH1" (verified in PlanningWorksheetModalPageHandler)
+        // The handler will verify that CurrentWkshBatchName matches the expected batch name
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure OpenJnlSetsCorrectBatchWhenTemplateNameIsSetDirectlyOnRequisitionLine()
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        RequisitionWkshName1: Record "Requisition Wksh. Name";
+        RequisitionWkshName2: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        ReqJnlManagement: Codeunit ReqJnlManagement;
+        Item: Record Item;
+        CurrentJnlBatchName: Code[10];
+    begin
+        // [SCENARIO] ReqJnlManagement.OpenJnl uses Worksheet Template Name from the record when set directly
+        // instead of using GetRangeMax which would give incorrect results.
+        Initialize();
+
+        // [GIVEN] A Planning Worksheet template exists
+        CreatePlanningReqWkshTemplate(ReqWkshTemplate);
+
+        // [GIVEN] Two Planning Worksheet batches: "BATCH1" and "BATCH2"
+        CreateRequisitionWkshName(RequisitionWkshName1, ReqWkshTemplate.Name);
+        CreateRequisitionWkshName(RequisitionWkshName2, ReqWkshTemplate.Name);
+
+        // [GIVEN] An item with a requisition line in "BATCH1"
+        LibraryInventory.CreateItem(Item);
+        CreateRequisitionLine(RequisitionLine, ReqWkshTemplate.Name, RequisitionWkshName1.Name, Item."No.");
+
+        // [GIVEN] Set filters to simulate the scenario where the page is opened via record reference
+        // Note: When opened from ShowDocument, the record has Worksheet Template Name set directly
+        // but no filter on Journal Batch Name
+        RequisitionLine.SetRange("Worksheet Template Name", ReqWkshTemplate.Name);
+        RequisitionLine."Worksheet Template Name" := ReqWkshTemplate.Name;
+
+        // [WHEN] OpenJnl is called with the requisition line
+        CurrentJnlBatchName := RequisitionWkshName1.Name;
+        ReqJnlManagement.OpenJnl(CurrentJnlBatchName, RequisitionLine);
+
+        // [THEN] The batch name is correctly set to "BATCH1"
+        Assert.AreEqual(RequisitionWkshName1.Name, CurrentJnlBatchName, 'OpenJnl should use the correct batch name from the requisition line');
+
+        // [THEN] The Journal Batch Name filter is set correctly
+        Assert.AreEqual(RequisitionWkshName1.Name, RequisitionLine.GetFilter("Journal Batch Name"), 'Journal Batch Name filter should be set to the correct batch');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure OpenedFromBatchConditionWhenTemplateNameIsSet()
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        Item: Record Item;
+        OpenedFromBatch: Boolean;
+    begin
+        // [SCENARIO] The OpenedFromBatch condition should be TRUE when both Journal Batch Name
+        // and Worksheet Template Name are set (not empty), which is the case when navigating
+        // from Item Availability by Event.
+        Initialize();
+
+        // [GIVEN] A Planning Worksheet template and batch exist
+        CreatePlanningReqWkshTemplate(ReqWkshTemplate);
+        CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+
+        // [GIVEN] An item with a requisition line
+        LibraryInventory.CreateItem(Item);
+        CreateRequisitionLine(RequisitionLine, ReqWkshTemplate.Name, RequisitionWkshName.Name, Item."No.");
+
+        // [WHEN] Simulating the condition check from PlanningWorksheet.Page.al OnOpenPage
+        // The fix changed the condition from:
+        //   OpenedFromBatch := (Rec."Journal Batch Name" <> '') and (Rec."Worksheet Template Name" = '');
+        // To:
+        //   OpenedFromBatch := (Rec."Journal Batch Name" <> '') and (Rec."Worksheet Template Name" <> '');
+        OpenedFromBatch := (RequisitionLine."Journal Batch Name" <> '') and (RequisitionLine."Worksheet Template Name" <> '');
+
+        // [THEN] OpenedFromBatch should be TRUE because both fields are set
+        Assert.IsTrue(OpenedFromBatch, 'OpenedFromBatch should be TRUE when both Journal Batch Name and Worksheet Template Name are set');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM - Planning Worksheet Batch");
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM - Planning Worksheet Batch");
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM - Planning Worksheet Batch");
+    end;
+
+    local procedure CreatePlanningReqWkshTemplate(var ReqWkshTemplate: Record "Req. Wksh. Template")
+    begin
+        ReqWkshTemplate.Init();
+        ReqWkshTemplate.Name := LibraryUtility.GenerateRandomCode(ReqWkshTemplate.FieldNo(Name), DATABASE::"Req. Wksh. Template");
+        ReqWkshTemplate.Type := ReqWkshTemplate.Type::Planning;
+        ReqWkshTemplate."Page ID" := PAGE::"Planning Worksheet";
+        ReqWkshTemplate.Insert();
+    end;
+
+    local procedure CreateRequisitionWkshName(var RequisitionWkshName: Record "Requisition Wksh. Name"; WorksheetTemplateName: Code[10])
+    begin
+        RequisitionWkshName.Init();
+        RequisitionWkshName.Validate("Worksheet Template Name", WorksheetTemplateName);
+        RequisitionWkshName.Validate(
+            Name,
+            CopyStr(
+                LibraryUtility.GenerateRandomCode(RequisitionWkshName.FieldNo(Name), DATABASE::"Requisition Wksh. Name"),
+                1, LibraryUtility.GetFieldLength(DATABASE::"Requisition Wksh. Name", RequisitionWkshName.FieldNo(Name))));
+        RequisitionWkshName.Insert(true);
+    end;
+
+    local procedure CreateRequisitionLine(var RequisitionLine: Record "Requisition Line"; WorksheetTemplateName: Code[10]; JournalBatchName: Code[10]; ItemNo: Code[20])
+    var
+        RecRef: RecordRef;
+    begin
+        RequisitionLine.Init();
+        RequisitionLine.Validate("Worksheet Template Name", WorksheetTemplateName);
+        RequisitionLine.Validate("Journal Batch Name", JournalBatchName);
+        RecRef.GetTable(RequisitionLine);
+        RequisitionLine.Validate("Line No.", LibraryUtility.GetNewLineNo(RecRef, RequisitionLine.FieldNo("Line No.")));
+        RequisitionLine.Type := RequisitionLine.Type::Item;
+        RequisitionLine."No." := ItemNo;
+        RequisitionLine.Quantity := 10;
+        RequisitionLine.Insert(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PlanningWorksheetModalPageHandler(var PlanningWorksheet: TestPage "Planning Worksheet")
+    var
+        ExpectedBatchName: Code[10];
+    begin
+        // Verify that the correct batch is displayed
+        ExpectedBatchName := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(ExpectedBatchName));
+        Assert.AreEqual(ExpectedBatchName, PlanningWorksheet.CurrentWkshBatchName.Value, 'Planning Worksheet opened with wrong batch name');
+        PlanningWorksheet.OK().Invoke();
+    end;
+}

