+
+codeunit 139545 "EXR FA Analysis Excel Reports"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryFixedAsset: Codeunit "Library - Fixed Asset";
+        LibraryReportDataset: Codeunit "Library - Report Dataset";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('EXRFixedAssetAnalysisExcelHandler')]
+    procedure FixedAssetAnalysisExportsAcquisitionDateWhenFAPostingTypesCreated()
+    var
+        FixedAsset: Record "Fixed Asset";
+        FADepreciationBook: Record "FA Depreciation Book";
+        DepreciationBook: Record "Depreciation Book";
+        FAPostingType: Record "FA Posting Type";
+        Variant: Variant;
+        RequestPageXml: Text;
+        AcquisitionDateValue: Date;
+        ExpectedAcquisitionDate: Date;
+    begin
+        // [SCENARIO] The Fixed Asset Analysis Excel report should export the Acquisition Date for each Fixed Asset
+        // [GIVEN] A Fixed Asset with an Acquisition Date set
+        CleanUpFAData();
+
+        // Create depreciation book
+        LibraryFixedAsset.CreateDepreciationBook(DepreciationBook);
+
+        // Create Fixed Asset
+        LibraryFixedAsset.CreateFixedAsset(FixedAsset);
+
+        // Create FA Depreciation Book with Acquisition Date
+        LibraryFixedAsset.CreateFADepreciationBook(FADepreciationBook, FixedAsset."No.", DepreciationBook.Code);
+        ExpectedAcquisitionDate := WorkDate() - 30;
+        FADepreciationBook."Acquisition Date" := ExpectedAcquisitionDate;
+        FADepreciationBook.Modify();
+
+        // Ensure FA Posting Types exist (this is what the fix adds to OnOpenPage)
+        FAPostingType.CreateTypes();
+
+        // Store the depreciation book code for the request page handler
+        LibraryVariableStorage.Enqueue(DepreciationBook.Code);
+
+        Commit();
+
+        // [WHEN] Running the Fixed Asset Analysis Excel report
+        RequestPageXml := Report.RunRequestPage(Report::"EXR Fixed Asset Analysis Excel", RequestPageXml);
+        LibraryReportDataset.RunReportAndLoad(Report::"EXR Fixed Asset Analysis Excel", Variant, RequestPageXml);
+
+        // [THEN] The Acquisition Date should be exported for the Fixed Asset
+        LibraryReportDataset.SetXmlNodeList('DataItem[@name="FAPostingType"]');
+        Assert.IsTrue(LibraryReportDataset.RowCount() > 0, 'There should be FA Posting Type rows exported');
+
+        LibraryReportDataset.GetNextRow();
+        LibraryReportDataset.FindCurrentRowValue('AcquisitionDateField', Variant);
+        AcquisitionDateValue := Variant;
+        Assert.AreEqual(ExpectedAcquisitionDate, AcquisitionDateValue, 'The Acquisition Date should match the FA Depreciation Book Acquisition Date');
+    end;
+
+    [Test]
+    [HandlerFunctions('EXRFixedAssetAnalysisExcelHandler')]
+    procedure FixedAssetAnalysisExportsDataWhenFAPostingTypesExist()
+    var
+        FixedAsset: Record "Fixed Asset";
+        FADepreciationBook: Record "FA Depreciation Book";
+        DepreciationBook: Record "Depreciation Book";
+        FAPostingType: Record "FA Posting Type";
+        Variant: Variant;
+        RequestPageXml: Text;
+    begin
+        // [SCENARIO] The Fixed Asset Analysis Excel report should export FA Posting Type data when types are created
+        // [GIVEN] A Fixed Asset with an Acquisition Date set and FA Posting Types created
+        CleanUpFAData();
+
+        // Create depreciation book
+        LibraryFixedAsset.CreateDepreciationBook(DepreciationBook);
+
+        // Create Fixed Asset
+        LibraryFixedAsset.CreateFixedAsset(FixedAsset);
+
+        // Create FA Depreciation Book with Acquisition Date
+        LibraryFixedAsset.CreateFADepreciationBook(FADepreciationBook, FixedAsset."No.", DepreciationBook.Code);
+        FADepreciationBook."Acquisition Date" := WorkDate() - 30;
+        FADepreciationBook.Modify();
+
+        // Create FA Posting Types - this is the key fix being tested
+        FAPostingType.CreateTypes();
+
+        // Store the depreciation book code for the request page handler
+        LibraryVariableStorage.Enqueue(DepreciationBook.Code);
+
+        Commit();
+
+        // [WHEN] Running the Fixed Asset Analysis Excel report
+        RequestPageXml := Report.RunRequestPage(Report::"EXR Fixed Asset Analysis Excel", RequestPageXml);
+        LibraryReportDataset.RunReportAndLoad(Report::"EXR Fixed Asset Analysis Excel", Variant, RequestPageXml);
+
+        // [THEN] FA Posting Type rows should be exported (indicating the nested dataitem was processed)
+        LibraryReportDataset.SetXmlNodeList('DataItem[@name="FAPostingType"]');
+        Assert.IsTrue(LibraryReportDataset.RowCount() > 0, 'FA Posting Type rows should be exported when FA Posting Types exist');
+    end;
+
+    local procedure CleanUpFAData()
+    var
+        FixedAsset: Record "Fixed Asset";
+        FADepreciationBook: Record "FA Depreciation Book";
+        FAPostingType: Record "FA Posting Type";
+    begin
+        FADepreciationBook.DeleteAll();
+        FixedAsset.DeleteAll();
+        FAPostingType.DeleteAll();
+    end;
+
+    [RequestPageHandler]
+    procedure EXRFixedAssetAnalysisExcelHandler(var EXRFixedAssetAnalysisExcel: TestRequestPage "EXR Fixed Asset Analysis Excel")
+    begin
+        EXRFixedAssetAnalysisExcel.DepreciationBookCodeField.Value := LibraryVariableStorage.DequeueText();
+        EXRFixedAssetAnalysisExcel.StartingDateField.Value := Format(WorkDate() - 60);
+        EXRFixedAssetAnalysisExcel.EndingDateField.Value := Format(WorkDate());
+        EXRFixedAssetAnalysisExcel.OK().Invoke();
+    end;
+}

