+        // Line 20000: Place - Item, Qty = 900
+        // Line 30000: Take - Item, Qty = 900
+        // Line 40000: Place - Item, Qty = 900
+        MockWhseActivityHeader(WarehouseActivityHeader, WarehouseActivityHeader.Type::Pick, LocationCode);
