+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+        ValueEntry: Record "Value Entry";
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO] Renaming an Item No. should succeed when Item has Variants with posted Value Entries
+        // The OnBeforeRenameEvent of Item Variant should skip validation when RunTrigger is false (cascade rename)
+        Initialize();
+
+        // [GIVEN] Create Item
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create Item Variant for the Item
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Post Item Journal for the Item with Variant Code (creates Item Ledger Entry and Value Entry)
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LibraryRandom.RandDecInRange(10, 20, 2));
+        ItemJournalLine.Validate("Variant Code", ItemVariant.Code);
+        ItemJournalLine.Validate("Unit Amount", LibraryRandom.RandDecInRange(10, 100, 2));
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // [GIVEN] Post another Item Journal for the Item without Variant Code (blank variant)
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LibraryRandom.RandDecInRange(10, 20, 2));
+        ItemJournalLine.Validate("Unit Amount", LibraryRandom.RandDecInRange(10, 100, 2));
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // [GIVEN] Verify Value Entries exist for both Variant and blank Variant
+        ValueEntry.SetRange("Item No.", Item."No.");
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        Assert.RecordIsNotEmpty(ValueEntry);
+        ValueEntry.SetRange("Variant Code", '');
+        Assert.RecordIsNotEmpty(ValueEntry);
+
+        // [WHEN] Rename the Item No. (this triggers cascade rename of ItemVariant with RunTrigger = false)
+        NewItemNo := LibraryUtility.GenerateRandomCode(Item.FieldNo("No."), Database::Item);
+        Item.Rename(NewItemNo);
+
+        // [THEN] No error is raised and Item Variant is renamed with the new Item No.
+        ItemVariant.SetRange("Item No.", NewItemNo);
+        Assert.RecordIsNotEmpty(ItemVariant);
+
+        // [THEN] Value Entries are updated with the new Item No.
+        ValueEntry.SetRange("Item No.", NewItemNo);
+        ValueEntry.SetRange("Variant Code", '');
+        Assert.RecordIsNotEmpty(ValueEntry);
+    end;
+
