+codeunit 139614 "Shpfy Copy Invoice Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryAssert: Codeunit "Library Assert";
+        Any: Codeunit Any;
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure CopyPostedSalesInvoiceClearsShopifyFields()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        ToSalesHeader: Record "Sales Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        PostedInvoiceNo: Code[20];
+        ShpfyOrderId: BigInteger;
+        ShpfyOrderNo: Code[50];
+        ShpfyRefundId: BigInteger;
+    begin
+        // [SCENARIO] When copying a posted sales invoice to a new sales document, the Shopify Order Id, Order No., and Refund Id should be cleared
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No., and Refund Id populated
+        Initialize();
+
+        ShpfyOrderId := Any.IntegerInRange(1, 999999999);
+        ShpfyOrderNo := CopyStr(Any.AlphanumericText(20), 1, MaxStrLen(ShpfyOrderNo));
+        ShpfyRefundId := Any.IntegerInRange(1, 999999999);
+        PostedInvoiceNo := CreateAndPostSalesInvoiceWithShopifyFields(ShpfyOrderId, ShpfyOrderNo, ShpfyRefundId);
+
+        // Verify the posted invoice has the Shopify fields populated
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        LibraryAssert.AreEqual(ShpfyOrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shpfy Order Id');
+        LibraryAssert.AreEqual(ShpfyOrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shpfy Order No.');
+
+        // [GIVEN] A new sales invoice header to copy into
+        LibrarySales.CreateSalesHeader(ToSalesHeader, ToSalesHeader."Document Type"::Invoice, SalesInvoiceHeader."Sell-to Customer No.");
+
+        // [WHEN] Copying the posted sales invoice to a new sales invoice
+        CopyDocumentMgt.SetProperties(true, false, false, false, true, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, ToSalesHeader);
+
+        // [THEN] The new sales invoice should have empty Shopify fields (Shpfy Order Id, Order No., and Refund Id should be cleared)
+        ToSalesHeader.Get(ToSalesHeader."Document Type", ToSalesHeader."No.");
+        LibraryAssert.AreEqual(0, ToSalesHeader."Shpfy Order Id", 'Shpfy Order Id should be cleared after copy');
+        LibraryAssert.AreEqual('', ToSalesHeader."Shpfy Order No.", 'Shpfy Order No. should be cleared after copy');
+        LibraryAssert.AreEqual(0, ToSalesHeader."Shpfy Refund Id", 'Shpfy Refund Id should be cleared after copy');
+    end;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+
+        LibraryRandom.Init();
+        IsInitialized := true;
+        Commit();
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithShopifyFields(ShpfyOrderId: BigInteger; ShpfyOrderNo: Code[50]; ShpfyRefundId: BigInteger): Code[20]
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        Item: Record Item;
+    begin
+        // Create a customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // Create a sales invoice
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+
+        // Set the Shopify fields on the sales header
+        SalesHeader."Shpfy Order Id" := ShpfyOrderId;
+        SalesHeader."Shpfy Order No." := ShpfyOrderNo;
+        SalesHeader."Shpfy Refund Id" := ShpfyRefundId;
+        SalesHeader.Modify();
+
+        // Create a sales line with an item
+        LibrarySales.CreateSimpleItemSalesLine(SalesLine, SalesHeader, "Sales Line Type"::Item);
+        SalesLine.Validate(Quantity, 1);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLine.Modify(true);
+
+        // Post the sales invoice
+        exit(LibrarySales.PostSalesDocument(SalesHeader, false, true));
+    end;
+}

