diff --git a/App/Layers/W1/Tests/Job/PurchaseDocFromJobTest.Codeunit.al b/App/Layers/W1/Tests/Job/PurchaseDocFromJobTest.Codeunit.al
new file mode 100644
index 00000000..1ee24fcc
--- /dev/null
+++ b/App/Layers/W1/Tests/Job/PurchaseDocFromJobTest.Codeunit.al
@@ -0,0 +1,134 @@
+codeunit 136325 "Purchase Doc From Job Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase] [Job] [UT]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SelectionFilterBuiltCorrectlyWhenLinesInsertedOutOfOrder()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobPlanningLineByPK: Record "Job Planning Line";
+        JobPlanningLine1: Record "Job Planning Line";
+        JobPlanningLine2: Record "Job Planning Line";
+        JobPlanningLine3: Record "Job Planning Line";
+        SelectionFilterMgt: Codeunit System.Text.SelectionFilterManagement;
+        RecRef: RecordRef;
+        RecRefByPK: RecordRef;
+        FilterWithSortedKey: Text;
+        FilterWithPrimaryKey: Text;
+        EntryNo1: Integer;
+        EntryNo2: Integer;
+        EntryNo3: Integer;
+    begin
+        // [SCENARIO 535294] When creating purchase order from project, the filter should correctly include all lines
+        // regardless of the order in which lines were inserted
+        // [GIVEN] A Job with Job Task
+        Initialize();
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] First Job Planning Line created with Line No. 20000
+        CreateJobPlanningLineWithLineNo(JobPlanningLine1, JobTask, 20000);
+        EntryNo1 := JobPlanningLine1."Job Contract Entry No.";
+
+        // [GIVEN] Second Job Planning Line created with Line No. 10000 (before the first one)
+        // This simulates adding a line "before" existing ones in the UI
+        CreateJobPlanningLineWithLineNo(JobPlanningLine2, JobTask, 10000);
+        EntryNo2 := JobPlanningLine2."Job Contract Entry No.";
+
+        // [GIVEN] Third Job Planning Line created with Line No. 30000
+        CreateJobPlanningLineWithLineNo(JobPlanningLine3, JobTask, 30000);
+        EntryNo3 := JobPlanningLine3."Job Contract Entry No.";
+
+        // Verify that the Job Contract Entry No. values are ascending based on creation order, not Line No. order
+        // Line No. order is 10000 (EntryNo2), 20000 (EntryNo1), 30000 (EntryNo3)
+        // But Entry No. order is EntryNo1 < EntryNo2 < EntryNo3
+        Assert.IsTrue(EntryNo1 < EntryNo2, 'Entry No. 1 should be less than Entry No. 2');
+        Assert.IsTrue(EntryNo2 < EntryNo3, 'Entry No. 2 should be less than Entry No. 3');
+
+        // [WHEN] Building filter with SetCurrentKey on Job Contract Entry No. (the fix)
+        JobPlanningLine.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLine.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.SetCurrentKey("Job Contract Entry No.");
+        JobPlanningLine.FindSet();
+        RecRef.GetTable(JobPlanningLine);
+        FilterWithSortedKey := SelectionFilterMgt.GetSelectionFilter(RecRef, JobPlanningLine.FieldNo("Job Contract Entry No."));
+
+        // [WHEN] Building filter WITHOUT SetCurrentKey (the bug behavior - uses primary key order)
+        JobPlanningLineByPK.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLineByPK.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLineByPK.SetRange("Job Task No.", JobTask."Job Task No.");
+        // No SetCurrentKey - uses primary key (Line No.) order
+        JobPlanningLineByPK.FindSet();
+        RecRefByPK.GetTable(JobPlanningLineByPK);
+        FilterWithPrimaryKey := SelectionFilterMgt.GetSelectionFilter(RecRefByPK, JobPlanningLineByPK.FieldNo("Job Contract Entry No."));
+
+        // [THEN] Filter with sorted key should be a valid ascending range
+        // The expected filter should be: "EntryNo1..EntryNo3" (correct ascending range)
+        Assert.AreEqual(StrSubstNo('%1..%2', EntryNo1, EntryNo3), FilterWithSortedKey, 
+            'Filter with SetCurrentKey should be a proper range from lowest to highest Job Contract Entry No.');
+
+        // [THEN] Filter with primary key would produce an invalid descending "range" like "EntryNo2..EntryNo1|EntryNo3"
+        // Because records are returned in Line No. order: 10000->EntryNo2, 20000->EntryNo1, 30000->EntryNo3
+        // This is a pipe-separated filter instead of a simple range, which is incorrect for filtering purposes
+        Assert.AreNotEqual(FilterWithSortedKey, FilterWithPrimaryKey,
+            'Filter without SetCurrentKey should be different (and incorrect) due to wrong order');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Purchase Doc From Job Test");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Purchase Doc From Job Test");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryJob.SetJobNoSeriesCode();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Purchase Doc From Job Test");
