index 00000000..8ff41e0f
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMWhseShptPostPreview.Codeunit.al
@@ -0,0 +1,135 @@
+codeunit 137916 "SCM Whse. Shpt Post Preview"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Post Preview] [Warehouse Shipment]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        IsInitialized: Boolean;
+        WrongPostPreviewErr: Label 'Expected empty error from Preview. Actual error: ';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PreviewWhseShipmentTransferOrder_LineExistsAfterPreview()
+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        Item: Record Item;
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        WarehouseEmployee: Record "Warehouse Employee";
+        WhsePostShipmentYesNo: Codeunit "Whse.-Post Shipment (Yes/No)";
+        GLPostingPreview: TestPage "G/L Posting Preview";
+        Quantity: Decimal;
+        WhseShptNo: Code[20];
+    begin
+        // [FEATURE] [Transfer Order] [Warehouse Shipment] [Preview Posting]
+        // [SCENARIO] Preview Posting of Warehouse Shipment linked to a Transfer Order should not remove the Warehouse Shipment Line.
+        // Bug: Warehouse shipment line linked to a Transfer Order seems to disappear after Preview posting.
+        Initialize();
+
+        // [GIVEN] Location "FROM" with Require Shipment and Require Receive enabled
+        CreateLocationWithShipmentAndReceive(LocationFrom);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, LocationFrom.Code, true);
+
+        // [GIVEN] Location "TO" for destination
+        LibraryWarehouse.CreateLocation(LocationTo);
+
+        // [GIVEN] In-Transit Location
+        LibraryWarehouse.CreateInTransitLocation(LocationInTransit);
+
+        // [GIVEN] Item with positive inventory at "FROM" location
+        LibraryInventory.CreateItem(Item);
+        Quantity := LibraryRandom.RandIntInRange(5, 20);
+        LibraryInventory.PostPositiveAdjustment(
+            Item, LocationFrom.Code, '', '', Quantity, WorkDate(), LibraryRandom.RandInt(10));
+
+        // [GIVEN] Transfer Order from "FROM" to "TO" with the Item
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Quantity);
+        LibraryInventory.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Warehouse Shipment created from Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+        FindWarehouseShipmentLine(WarehouseShipmentLine, WarehouseShipmentLine."Source Document"::"Outbound Transfer", TransferHeader."No.");
+        WhseShptNo := WarehouseShipmentLine."No.";
+        WarehouseShipmentHeader.Get(WhseShptNo);
+
+        Commit();
+
+        // [WHEN] Preview Posting is invoked on the Warehouse Shipment
+        GLPostingPreview.Trap();
+        asserterror WhsePostShipmentYesNo.Preview(WarehouseShipmentLine);
+        Assert.AreEqual('', GetLastErrorText, WrongPostPreviewErr + GetLastErrorText);
+        GLPostingPreview.OK().Invoke();
+
+        // [THEN] Warehouse Shipment Line still exists after preview
+        WarehouseShipmentLine.Reset();
+        WarehouseShipmentLine.SetRange("No.", WhseShptNo);
+        WarehouseShipmentLine.SetRange("Source Document", WarehouseShipmentLine."Source Document"::"Outbound Transfer");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.RecordIsNotEmpty(WarehouseShipmentLine);
+
+        // [THEN] Warehouse Shipment Header still exists after preview
+        Assert.IsTrue(WarehouseShipmentHeader.Get(WhseShptNo), 'Warehouse Shipment Header should still exist after preview posting');
+
+        // [THEN] Warehouse Shipment Line quantity should be unchanged
+        WarehouseShipmentLine.FindFirst();
+        Assert.AreEqual(Quantity, WarehouseShipmentLine.Quantity, 'Warehouse Shipment Line Quantity should be unchanged after preview');
+        Assert.AreEqual(Quantity, WarehouseShipmentLine."Qty. Outstanding", 'Warehouse Shipment Line Qty. Outstanding should be unchanged after preview');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Whse. Shpt Post Preview");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Whse. Shpt Post Preview");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+        WarehouseEmployee.DeleteAll(true);
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Whse. Shpt Post Preview");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        WarehouseSetup: Record "Warehouse Setup";
+    begin
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+    end;
+
+    local procedure CreateLocationWithShipmentAndReceive(var Location: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, false, false, false, true, true);
+    end;
+
+    local procedure FindWarehouseShipmentLine(var WarehouseShipmentLine: Record "Warehouse Shipment Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20])
+    begin
+        WarehouseShipmentLine.SetRange("Source Document", SourceDocument);
+        WarehouseShipmentLine.SetRange("Source No.", SourceNo);
+        WarehouseShipmentLine.FindFirst();
+    end;
+}

