+    [Test]
+    [HandlerFunctions('ItemTrackingPageHandler,ItemTrackingSummaryPageHandler')]
+    [Scope('OnPrem')]
+    procedure PostConsumptionReservedToMultipleLotTrackedILEs()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        LotNo: Code[50];
+        Qty1: Decimal;
+        Qty2: Decimal;
+        Qty3: Decimal;
+        TotalQty: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Item Tracking] [Reservation] [Consumption]
+        // [SCENARIO] Post consumption that is reserved to multiple lot tracked ILEs with same lot number.
+        // When a component item with Reserve = Always is reserved to multiple ILEs with the same lot,
+        // posting consumption should succeed without "insufficient quantity" error.
+
+        // [GIVEN] Initialize and set up location
+        Initialize();
+        UpdateManufacturingSetupComponentsAtLocation(LocationGreen.Code);
+
+        // [GIVEN] Create component item with lot tracking and Reserve = Always
+        CreateItemWithItemTrackingCode(CompItem, CreateItemTrackingCode());
+        CompItem.Validate(Reserve, CompItem.Reserve::Always);
+        CompItem.Modify(true);
+
+        // [GIVEN] Create production item with component in BOM
+        CreateCertifiedProductionBOM(ProductionBOMHeader, CompItem);
+        CreateProductionItem(ProdItem, ProductionBOMHeader."No.");
+
+        // [GIVEN] Create 3 positive adjustment entries with quantities 5, 10, 20 for the same lot number
+        LotNo := LibraryUtility.GenerateGUID();
+        Qty1 := 5;
+        Qty2 := 10;
+        Qty3 := 20;
+        TotalQty := Qty1 + Qty2 + Qty3;
+
+        // Post first adjustment with lot tracking
+        CreateItemJournalLine(ItemJournalLine, CompItem."No.", Qty1, '', LocationGreen.Code);
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Manual Lot No.");
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(Qty1);
+        ItemJournalLine.OpenItemTrackingLines(false);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // Post second adjustment with same lot number
+        CreateItemJournalLine(ItemJournalLine, CompItem."No.", Qty2, '', LocationGreen.Code);
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Manual Lot No.");
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(Qty2);
+        ItemJournalLine.OpenItemTrackingLines(false);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // Post third adjustment with same lot number
+        CreateItemJournalLine(ItemJournalLine, CompItem."No.", Qty3, '', LocationGreen.Code);
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Manual Lot No.");
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(Qty3);
+        ItemJournalLine.OpenItemTrackingLines(false);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // [GIVEN] Create and refresh released production order for total quantity
+        CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProdItem."No.", TotalQty, LocationGreen.Code, '');
+
+        // [GIVEN] Verify component is auto-reserved to the 3 ILEs (Reserve = Always)
+        FindProductionOrderComponent(ProdOrderComponent, ProductionOrder."No.");
+        ProdOrderComponent.CalcFields("Reserved Quantity");
+        Assert.AreEqual(TotalQty, ProdOrderComponent."Reserved Quantity", 'Component should be fully reserved');
+
+        // [WHEN] Post consumption with item tracking for the full quantity
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Select Entries");
+        CreateAndPostConsumptionJournalWithItemTracking(ProductionOrder."No.", true);
+
+        // [THEN] Consumption is posted successfully without error
+        ItemLedgerEntry.SetRange("Item No.", CompItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Consumption);
+        ItemLedgerEntry.SetRange("Order No.", ProductionOrder."No.");
+        ItemLedgerEntry.CalcSums(Quantity);
+        Assert.AreEqual(-TotalQty, ItemLedgerEntry.Quantity, 'Total consumption quantity should match');
+    end;
