+    [HandlerFunctions('ItemChargeAssignmentPageHandler,SuggestItemChargeAssgntByAmountHandler,PostedSalesDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure GetPostedDocLinesToReverseWithItemChargeWhenDefaultQtyToShipIsBlank()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        SalesHeader: Record "Sales Header";
+        SalesHeaderReturn: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesLineCharge: Record "Sales Line";
+        Item: Record Item;
+        ItemCharge: Record "Item Charge";
+        Customer: Record Customer;
+        OriginalDefaultQtyToShip: Option;
+    begin
+        // [FEATURE] [Item Charge] [Sales Return Order] [Get Posted Document Lines to Reverse]
+        // [SCENARIO] Item Charge line can be pulled into Sales Return Order using Get Posted Document Lines to Reverse 
+        // when Default Quantity to Ship is set to Blank in Sales & Receivables Setup.
+        Initialize();
+
+        // [GIVEN] Set "Default Quantity to Ship" to "Blank" in Sales & Receivables Setup
+        SalesReceivablesSetup.Get();
+        OriginalDefaultQtyToShip := SalesReceivablesSetup."Default Quantity to Ship";
+        SalesReceivablesSetup."Default Quantity to Ship" := SalesReceivablesSetup."Default Quantity to Ship"::Blank;
+        SalesReceivablesSetup.Modify(true);
+
+        // [GIVEN] Create Sales Order with Item and Item Charge
+        LibrarySales.CreateCustomer(Customer);
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemCharge(ItemCharge);
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(5, 25));
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLine.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLineCharge, SalesHeader, SalesLineCharge.Type::"Charge (Item)", ItemCharge."No.", SalesLine.Quantity);
+        SalesLineCharge.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLineCharge.Modify(true);
+
+        // [GIVEN] Assign Item Charge to Item line
+        SalesLineCharge.ShowItemChargeAssgnt();
+
+        // [GIVEN] Update Qty. to Ship and Qty. to Invoice for proper posting
+        SalesLine.Find();
+        SalesLine.Validate("Qty. to Ship", SalesLine.Quantity);
+        SalesLine.Validate("Qty. to Invoice", SalesLine.Quantity);
+        SalesLine.Modify(true);
+
+        SalesLineCharge.Find();
+        SalesLineCharge.Validate("Qty. to Ship", SalesLineCharge.Quantity);
+        SalesLineCharge.Validate("Qty. to Invoice", SalesLineCharge.Quantity);
+        SalesLineCharge.Modify(true);
+
+        // [GIVEN] Post Sales Order (Ship and Invoice)
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] Create Sales Return Order for the same customer
+        LibrarySales.CreateSalesHeader(SalesHeaderReturn, SalesHeaderReturn."Document Type"::"Return Order", SalesHeader."Sell-to Customer No.");
+
+        // [WHEN] Run Get Posted Document Lines to Reverse for posted invoice
+        LibraryVariableStorage.Enqueue(1); // Posted Invoices option
+        SalesHeaderReturn.GetPstdDocLinesToReverse();
+
+        // [THEN] Verify that both Item and Item Charge lines are created in Sales Return Order
+        SalesLine.Reset();
+        SalesLine.SetRange("Document Type", SalesHeaderReturn."Document Type");
+        SalesLine.SetRange("Document No.", SalesHeaderReturn."No.");
+        SalesLine.SetRange(Type, SalesLine.Type::Item);
+        Assert.RecordIsNotEmpty(SalesLine);
+
+        SalesLine.SetRange(Type, SalesLine.Type::"Charge (Item)");
+        Assert.RecordIsNotEmpty(SalesLine);
+
+        // Restore original setup
+        SalesReceivablesSetup."Default Quantity to Ship" := OriginalDefaultQtyToShip;
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedSalesDocumentLinesHandler(var PostedSalesDocumentLines: TestPage "Posted Sales Document Lines")
+    var
+        DocumentType: Option "Posted Shipments","Posted Invoices","Posted Return Receipts","Posted Cr. Memos";
+        OptionValue: Integer;
+    begin
+        OptionValue := LibraryVariableStorage.DequeueInteger();
+        case OptionValue of
+            0:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Shipments"));
+            1:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Invoices"));
+            2:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Return Receipts"));
+            3:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Cr. Memos"));
+        end;
+        PostedSalesDocumentLines.OK().Invoke();
+    end;
 }

