+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        NewPurchOrderChoice: Option " ","Make Purch. Orders","Make Purch. Orders & Print","Copy to Req. Wksh";
+        CancelLineNo: Integer;
+        NewLineNo: Integer;
+        Quantity: Decimal;
+        PurchOrderReceiptDate: Date;
+        SalesShipmentDate: Date;
+    begin
+        // [FEATURE] [Carry Out Action Message] [Planning Worksheet]
+        // [SCENARIO 504310] When filtering Planning Worksheet lines by Action Message and running Carry Out Action Message,
+        // only lines matching the filter should be processed.
+        Initialize();
+
+        // [GIVEN] Create an item with Order reordering policy and Purchase replenishment
+        CreateOrderItem(Item, '', Item."Replenishment System"::Purchase);
+
+        // [GIVEN] Create a purchase order for the item with Expected Receipt Date = January 1st
+        Quantity := LibraryRandom.RandIntInRange(1, 10);
+        PurchOrderReceiptDate := CalcDate('<-1M>', WorkDate());
+        CreatePurchaseOrder(PurchaseHeader, Item."No.", PurchOrderReceiptDate, Quantity);
+
+        // [GIVEN] Create a sales order for the same item with Shipment Date set to a future date (different from purchase order)
+        SalesShipmentDate := CalcDate('<+1M>', WorkDate());
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Shipment Date", SalesShipmentDate);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Calculate Regenerative Plan - this should create Cancel (for existing PO) and New action message lines
+        CreateRequisitionWorksheetName(RequisitionWkshName);
+        Item.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate(), SalesShipmentDate);
+
+        // [GIVEN] Find the Cancel and New requisition lines
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Cancel line should exist');
+        CancelLineNo := RequisitionLine."Line No.";
+
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'New line should exist');
+        NewLineNo := RequisitionLine."Line No.";
+
+        // [GIVEN] Accept action message for BOTH lines (Cancel and New)
+        // This is important to test the filter - both lines are eligible for processing
+        RequisitionLine.SetRange("Action Message");
+        RequisitionLine.SetRange("Line No.", CancelLineNo);
+        RequisitionLine.FindFirst();
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        RequisitionLine.SetRange("Line No.", NewLineNo);
+        RequisitionLine.FindFirst();
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        // [WHEN] Filter requisition lines by Action Message = Cancel and run Carry Out Action Message
+        // Without the fix, the Action Message filter would be ignored and BOTH lines would be processed
+        // With the fix, only the Cancel line should be processed
+        RequisitionLine.SetRange("Line No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        LibraryPlanning.CarryOutPlanWksh(
+            RequisitionLine, 0, NewPurchOrderChoice::"Make Purch. Orders", 0, 0,
+            RequisitionLine."Worksheet Template Name", RequisitionLine."Journal Batch Name", '', '');
+
+        // [THEN] The Cancel line should be processed (Purchase Order should be deleted)
+        Assert.IsFalse(PurchaseHeader.Get(PurchaseHeader."Document Type"::Order, PurchaseHeader."No."), 'Purchase Order should be deleted by Cancel action');
+
+        // [THEN] The New line should NOT be processed (should still exist in requisition worksheet)
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        RequisitionLine.SetRange("Line No.", NewLineNo);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'New line should still exist because it was not in the filter');
+    end;
+
