+        PurchQty: Decimal;
+        PutAwayNo: Code[20];
+        TotalLinesBeforeRegister: Integer;
+    begin
+        // [FEATURE] [Put-Away] [Breakbulk] [UI]
+        // [SCENARIO] When registering a put-away with Breakbulk Filter = Yes from the UI, all put-away lines should be registered, not just the visible ones.
+        // Bug: With the old code, Copy(Rec) would inherit the filter on Breakbulk=false, causing only visible lines to be registered.
+        Initialize();
+        QtyPerUOM := LibraryRandom.RandIntInRange(5, 10);
+        PurchQty := LibraryRandom.RandIntInRange(10, 20);
+
+        // [GIVEN] Full WMS location with Allow Breakbulk = FALSE (forces breakbulk lines to be created).
+        LibraryWarehouse.CreateFullWMSLocation(Location, 1);
+        Location.Validate("Allow Breakbulk", false);
+        Location.Modify(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] Item with Base Unit of Measure = "PCS" and alternate Unit of Measure = "BOX". "BOX" contains "X" units of "PCS".
+        // [GIVEN] Put-away Unit of Measure Code in the item is "PCS" (base UOM).
+        LibraryInventory.CreateItem(Item);
+        CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        UpdateItemUOM(Item, ItemUnitOfMeasure.Code, '', Item."Base Unit of Measure");
+
+        // [GIVEN] Purchase Order for quantity in "BOX" UOM, posted warehouse receipt creates put-away with breakbulk lines.
+        CreateAndReleasePurchaseOrder(PurchaseHeader, Location.Code, Item."No.", PurchQty);
+        CreateAndPostWarehouseReceiptFromPurchaseOrder(PurchaseHeader);
+
+        // [GIVEN] Find the created put-away and count all lines (should include breakbulk lines).
+        FindWarehouseActivityLine(WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Purchase Order", PurchaseHeader."No.", WarehouseActivityLine."Activity Type"::"Put-away");
+        PutAwayNo := WarehouseActivityLine."No.";
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityLine.SetRange("No.", PutAwayNo);
+        TotalLinesBeforeRegister := WarehouseActivityLine.Count();
+
+        // [GIVEN] Set Breakbulk Filter = Yes on the Warehouse Activity Header.
+        WarehouseActivityHeader.Get(WarehouseActivityHeader.Type::"Put-away", PutAwayNo);
+        WarehouseActivityHeader.Validate("Breakbulk Filter", true);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Register the put-away from the Warehouse Put-away page (using UI action that invokes RegisterPutAwayYesNo).
+        WarehousePutAwayPage.OpenEdit();
+        WarehousePutAwayPage.FILTER.SetFilter("No.", PutAwayNo);
+        WarehousePutAwayPage."Autofill Qty. to Handle".Invoke();
+        WarehousePutAwayPage."&Register Put-away".Invoke();
+        WarehousePutAwayPage.Close();
+
+        // [THEN] All put-away lines should be registered (the Warehouse Activity Lines should no longer exist).
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityLine.SetRange("No.", PutAwayNo);
+        Assert.RecordIsEmpty(WarehouseActivityLine);
+
+        // [THEN] The registered warehouse activity lines count should match the original lines count.
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::"Put-away");
+        RegisteredWhseActivityLine.SetRange("Source Document", RegisteredWhseActivityLine."Source Document"::"Purchase Order");
+        RegisteredWhseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        Assert.AreEqual(TotalLinesBeforeRegister, RegisteredWhseActivityLine.Count(), 'All put-away lines should be registered when Breakbulk Filter is enabled.');
+    end;
