+    [Test]
+    [Scope('OnPrem')]
+    procedure MfgOverheadCostWithMultipleProdOrderLines()
+    var
+        RawItem: Record Item;
+        FinishedItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: array[2] of Record "Prod. Order Line";
+        MfgCostCalculationMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCost: Decimal;
+        TotalExpMfgOvhdCost: Decimal;
+        RawItemUnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        LineQty: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Manufacturing Overhead]
+        // [SCENARIO] Manufacturing overhead should be calculated correctly when a production order has multiple lines
+        // The expected overhead should equal Indirect Cost % * Total Material Cost, regardless of number of lines
+
+        Initialize();
+
+        // [GIVEN] Raw material item with Unit Cost = 100
+        RawItemUnitCost := 100;
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", RawItemUnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] Production BOM with raw item, Qty per = 1
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, RawItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, RawItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Finished goods item with Indirect Cost % = 10 and assigned production BOM
+        IndirectCostPct := 10;
+        LibraryInventory.CreateItem(FinishedItem);
+        FinishedItem.Validate("Replenishment System", FinishedItem."Replenishment System"::"Prod. Order");
+        FinishedItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedItem.Validate("Indirect Cost %", IndirectCostPct);
+        FinishedItem.Modify(true);
+
+        // [GIVEN] Released production order with two lines, each with Qty = 10 (total 20)
+        LineQty := 10;
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, FinishedItem."No.", 0);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine[1], ProductionOrder.Status, ProductionOrder."No.", FinishedItem."No.", '', '', LineQty);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine[2], ProductionOrder.Status, ProductionOrder."No.", FinishedItem."No.", '', '', LineQty);
+
+        // [GIVEN] Refresh production order (components only, not lines)
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [WHEN] Calculate expected costs for each production order line
+        ExpMatCost := 0;
+        ExpCapDirCost := 0;
+        ExpSubDirCost := 0;
+        ExpCapOvhdCost := 0;
+        ExpMfgOvhdCost := 0;
+
+        ProdOrderLine[1].Find();
+        MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine[1], ShareOfTotalCapCost);
+        MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+            ProdOrderLine[1], ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+
+        ProdOrderLine[2].Find();
+        MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine[2], ShareOfTotalCapCost);
+        MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+            ProdOrderLine[2], ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+
+        TotalExpMfgOvhdCost := ExpMfgOvhdCost;
+
+        // [THEN] Total material cost should be 2000 (20 units * 100 unit cost)
