diff --git a/App/Layers/W1/Tests/ERM/ReminderLevelCommunicationTests.Codeunit.al b/App/Layers/W1/Tests/ERM/ReminderLevelCommunicationTests.Codeunit.al
new file mode 100644
index 00000000..ed1c7f8d
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/ReminderLevelCommunicationTests.Codeunit.al
@@ -0,0 +1,74 @@
+codeunit 134980 "Reminder Level Comm. Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerNo,LanguagesModalPageHandler')]
+    procedure AddTextForLanguageWhenNoAttachmentTextsExist()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderLevelCommunicationPage: TestPage "Reminder Level Communication";
+        LanguageCode: Code[10];
+    begin
+        // [FEATURE] [Reminder Level Communication]
+        // [SCENARIO] User can add text for language on Reminder Level Communication page when no attachment texts exist yet
+        // This test verifies the fix for the error "A reminder attachment text cannot be created without an ID"
+        // which occurred when adding text for language in Reminder Level Communication without existing attachment texts
+
+        // [GIVEN] A reminder term and level without any attachment texts (Reminder Attachment Text is null GUID)
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // Ensure the level has no attachment text
+        ReminderLevel.Get(ReminderTerms.Code, ReminderLevel."No.");
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Expected Reminder Attachment Text to be empty initially');
+
+        // [GIVEN] A language code to use for the new text
+        LanguageCode := LibraryERM.GetAnyLanguageDifferentFromCurrent();
+        LibraryVariableStorage.Enqueue(LanguageCode);
+
+        // [WHEN] User opens the Reminder Level Communication page (declining default text creation) and clicks "Add text for language..."
+        // The ConfirmHandlerNo handles the two confirmation dialogs that appear on page open
+        // The LanguagesModalPageHandler selects the language
+        ReminderLevelCommunicationPage.OpenEdit();
+        ReminderLevelCommunicationPage.GoToRecord(ReminderLevel);
+        ReminderLevelCommunicationPage."Add New Language".Invoke();
+
+        // [THEN] No error occurs and the Reminder Attachment Text is created for the selected language
+        ReminderLevel.Get(ReminderTerms.Code, ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Expected Reminder Attachment Text to be set');
+
+        ReminderAttachmentText.SetRange(Id, ReminderLevel."Reminder Attachment Text");
+        ReminderAttachmentText.SetRange("Language Code", LanguageCode);
+        Assert.IsTrue(ReminderAttachmentText.FindFirst(), 'Expected Reminder Attachment Text record to exist for selected language');
+
+        ReminderLevelCommunicationPage.Close();
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Reply No to the confirmation dialogs asking to create default attachment/email texts
+        Reply := false;
+    end;
+
+    [ModalPageHandler]
+    procedure LanguagesModalPageHandler(var Languages: TestPage "Languages")
+    var
+        LanguageCode: Code[10];
+    begin
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, 10);
+        Languages.Filter.SetFilter(Code, LanguageCode);
+        Languages.First();
+        Languages.OK().Invoke();
+    end;
+
+    var
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryERM: Codeunit "Library - ERM";
+        Assert: Codeunit Assert;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMReplanInputQuantity.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMReplanInputQuantity.Codeunit.al
new file mode 100644
index 00000000..30055b58
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMReplanInputQuantity.Codeunit.al
@@ -0,0 +1,206 @@
+codeunit 137999 "SCM Replan Input Quantity"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Replan Production Order] [SCM]
+        IsInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        CalendarMgt: Codeunit "Shop Calendar Management";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReplanProductionOrderRecalculatesInputQuantityAfterPartialOutput()
+    var
+        Item: Record Item;
+        ProductionOrder: Record "Production Order";
+        ProdOrderRoutingLine: Record "Prod. Order Routing Line";
+        Direction: Option Forward,Backward;
+        CalcMethod: Option "No Level","One Level","All Levels";
+        TotalQty: Decimal;
+        OutputQty: Decimal;
+        ExpectedInputQty: Decimal;
+    begin
+        // [FEATURE] [Replan] [Input Quantity]
+        // [SCENARIO 101005] Input quantity on Prod. Order Routing Line is recalculated when using Replan function after partial output has been posted.
+        // [SCENARIO 101005] According to https://learn.microsoft.com/en-us/dynamics365/business-central/production-how-to-replan-refresh-production-orders,
+        // [SCENARIO 101005] when you select "Plan" as "No Level", it should update the item schedule, including the starting/ending date-time, based on remaining quantity.
+
+        // [GIVEN] Production item with routing. Setup Time = 10, Run Time = 10.
+        Initialize();
+        TotalQty := 50;
+        OutputQty := 20;
+        ExpectedInputQty := TotalQty - OutputQty; // Remaining quantity = 30
+
+        CreateProductionItemWithOneLineRouting(Item, 10, 10, 0, 0, 080000T, 160000T, WorkDate());
+
+        // [GIVEN] Released production order for 50 pcs. Refresh.
+        CreateAndRefreshForwardReleasedProductionOrder(ProductionOrder, Item."No.", TotalQty, WorkDate(), 080000T);
+
+        // [GIVEN] Post output for 20 pcs.
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+        CreateAndPostOutputJnlLine(ProdOrderRoutingLine, Item."No.", OutputQty, 0, 0);
+
+        // [WHEN] Replan Production Order with Direction = Backward, CalcMethod = "No Level".
+        LibraryManufacturing.RunReplanProductionOrder(ProductionOrder, Direction::Backward, CalcMethod::"No Level");
+
+        // [THEN] "Input Quantity" on the prod. order routing line = 30 (remaining quantity after partial output).
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+        Assert.AreEqual(ExpectedInputQty, ProdOrderRoutingLine."Input Quantity",
+            'Input Quantity should be recalculated to remaining quantity after Replan.');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Replan Input Quantity");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Replan Input Quantity");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+        CalendarMgt.ClearInternals();
+        Commit();
+
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Replan Input Quantity");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateProductionItemWithOneLineRouting(var Item: Record Item; SetupTime: Decimal; RunTime: Decimal; WaitTime: Decimal; MoveTime: Decimal; WorkCenterStartTime: Time; WorkCenterEndTime: Time; DueDate: Date)
+    var
+        RoutingHeader: Record "Routing Header";
+        RoutingLine: Record "Routing Line";
+        CapacityUOM: Record "Capacity Unit of Measure";
+        WorkCenterCode: Code[20];
+    begin
+        WorkCenterCode :=
+          CreateWorkCenterWithShopCalendar(
+            CapacityUOM.Type::Minutes,
+            LibraryManufacturing.UpdateShopCalendarWorkingDaysCustomTime(WorkCenterStartTime, WorkCenterEndTime), 100, 1, DueDate);
+        CreateProductionItem(Item, Item."Reordering Policy"::"Lot-for-Lot", 0);
+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
+        CreateRoutingLineWithSendAhead(
+          RoutingLine, RoutingHeader, RoutingLine.Type::"Work Center", WorkCenterCode, SetupTime, RunTime, WaitTime, MoveTime, 0, 1, '10', '', '');
+        UpdateStatusOnRoutingHeader(RoutingHeader, RoutingHeader.Status::Certified);
+        Item.Validate("Routing No.", RoutingHeader."No.");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateProductionItem(var Item: Record Item; ReorderingPolicy: Enum "Reordering Policy"; ReorderQuantity: Decimal)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Reordering Policy", ReorderingPolicy);
+        if ReorderQuantity <> 0 then
+            Item.Validate("Reorder Quantity", ReorderQuantity);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateWorkCenterWithShopCalendar(CapacityUOMType: Enum "Capacity Unit of Measure"; ShopCalendarCode: Code[10]; Efficiency: Decimal; Capacity: Decimal; DueDate: Date): Code[20]
+    var
+        WorkCenter: Record "Work Center";
+        CapacityUOM: Record "Capacity Unit of Measure";
+    begin
+        LibraryManufacturing.CreateCapacityUnitOfMeasure(CapacityUOM, CapacityUOMType);
+        LibraryManufacturing.CreateWorkCenter(WorkCenter);
+        WorkCenter.Validate("Unit of Measure Code", CapacityUOM.Code);
+        WorkCenter.Validate("Shop Calendar Code", ShopCalendarCode);
+        WorkCenter.Validate(Efficiency, Efficiency);
+        WorkCenter.Validate(Capacity, Capacity);
+        WorkCenter.Modify(true);
+        LibraryManufacturing.CalculateWorkCenterCalendar(WorkCenter, CalcDate('<-1M>', DueDate), CalcDate('<1M>', DueDate));
+        exit(WorkCenter."No.");
+    end;
+
+    local procedure CreateRoutingLineWithSendAhead(var RoutingLine: Record "Routing Line"; RoutingHeader: Record "Routing Header"; Type: Enum "Capacity Type Routing"; No: Code[20]; SetupTime: Decimal; RunTime: Decimal; WaitTime: Decimal; MoveTime: Decimal; SendAheadQty: Decimal; ConcurrentCapacities: Decimal; OperationNo: Code[10]; NextOperationNo: Code[10]; PreviousOperationNo: Code[10])
+    begin
+        LibraryManufacturing.CreateRoutingLine(
+          RoutingHeader, RoutingLine, '', OperationNo, Type, No);
+        RoutingLine.Validate("Setup Time", SetupTime);
+        RoutingLine.Validate("Run Time", RunTime);
+        RoutingLine.Validate("Wait Time", WaitTime);
+        RoutingLine.Validate("Move Time", MoveTime);
+        RoutingLine.Validate("Send-Ahead Quantity", SendAheadQty);
+        RoutingLine.Validate("Concurrent Capacities", ConcurrentCapacities);
+        if NextOperationNo <> '' then
+            RoutingLine.Validate("Next Operation No.", NextOperationNo);
+        if PreviousOperationNo <> '' then
+            RoutingLine.Validate("Previous Operation No.", PreviousOperationNo);
+        RoutingLine.Modify(true);
+    end;
+
+    local procedure UpdateStatusOnRoutingHeader(var RoutingHeader: Record "Routing Header"; Status: Enum "Routing Status")
+    begin
+        RoutingHeader.Validate(Status, Status);
+        RoutingHeader.Modify(true);
+    end;
+
+    local procedure CreateAndRefreshForwardReleasedProductionOrder(var ProductionOrder: Record "Production Order"; SourceNo: Code[20]; Quantity: Decimal; StartingDate: Date; StartingTime: Time)
+    begin
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, SourceNo, Quantity);
+        ProductionOrder.SetUpdateEndDate();
+        ProductionOrder.Validate("Starting Date", StartingDate);
+        ProductionOrder.Validate("Starting Time", StartingTime);
+        ProductionOrder.Validate("Due Date", StartingDate + 1);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, true, true, true, true, false);
+    end;
+
+    local procedure CreateAndPostOutputJnlLine(ProdOrderRoutingLine: Record "Prod. Order Routing Line"; ItemNo: Code[20]; Qty: Decimal; SetupTime: Decimal; RunTime: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        CreateOutputJnlLineWithSetupRunTime(
+          ItemJournalLine, ProdOrderRoutingLine."Prod. Order No.", ItemNo, ProdOrderRoutingLine."Operation No.", SetupTime, RunTime);
+        ItemJournalLine.Validate("Output Quantity", Qty);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure CreateOutputJnlLineWithSetupRunTime(var ItemJournalLine: Record "Item Journal Line"; ProductionOrderNo: Code[20]; ItemNo: Code[20]; ProdOrderRtngLineOperationNo: Code[10]; SetupTime: Decimal; RunTime: Decimal)
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Output);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Output, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryManufacturing.CreateOutputJournal(
+          ItemJournalLine, ItemJournalTemplate, ItemJournalBatch, ItemNo, ProductionOrderNo);
+
+        ItemJournalLine.Validate("Operation No.", ProdOrderRtngLineOperationNo);
+        ItemJournalLine.Validate("Setup Time", SetupTime);
+        ItemJournalLine.Validate("Run Time", RunTime);
+        ItemJournalLine.Modify(true);
+    end;
+
+    local procedure FindFirstProdOrderRoutingLine(var ProdOrderRoutingLine: Record "Prod. Order Routing Line"; ProductionOrderNo: Code[20])
+    begin
+        ProdOrderRoutingLine.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderRoutingLine.FindFirst();
+    end;
+}

diff --git a/App/Layers/W1/Tests/Dimension/ERMDimensionLocations.Codeunit.al b/App/Layers/W1/Tests/Dimension/ERMDimensionLocations.Codeunit.al
