+        ExpectedAmountLCY: Decimal;
+    begin
+        // [FEATURE] [Currency] [Rounding]
+        // [SCENARIO 567890] Post Gen. Journal with Currency and Auto Acc. Group where 50/50 allocation causes Amount (LCY) rounding discrepancy
+        // [SCENARIO] The system should adjust Amount (LCY) on the last line to prevent inconsistency error
+
+        // [GIVEN] Currency EUR with exchange rate 1 EUR = 10.97223 LCY (causes rounding issues)
+        Initialize();
+        GLSetup.Get();
+
+        CurrencyCode := LibraryERM.CreateCurrencyWithRandomExchRates();
+        Currency.Get(CurrencyCode);
+        CurrencyExchangeRate.SetRange("Currency Code", CurrencyCode);
+        CurrencyExchangeRate.FindFirst();
+        // Set specific exchange rate that causes rounding: 1 FCY = 10.97223 LCY
+        CurrencyExchangeRate."Exchange Rate Amount" := 1;
+        CurrencyExchangeRate."Adjustment Exch. Rate Amount" := 1;
+        CurrencyExchangeRate."Relational Exch. Rate Amount" := 10.97223;
+        CurrencyExchangeRate."Relational Adjmt Exch Rate Amt" := 10.97223;
+        CurrencyExchangeRate.Modify();
+
+        // [GIVEN] Automatic Acc. Group "AAG" with three lines:
+        // [GIVEN]  Line1: "G/L Account No." = "ACC1", "Allocation %" = 50
+        // [GIVEN]  Line2: "G/L Account No." = "ACC2", "Allocation %" = 50
+        // [GIVEN]  Line3: "G/L Account No." = "ACC3", "Allocation %" = -100 (balancing)
+        LibraryAAC.CreateAutomaticAccountHeader(AutomaticAccountHeader);
+        AutoAccGroupNo := AutomaticAccountHeader."No.";
+
+        GLAccountNo1 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo2 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo3 := LibraryERM.CreateGLAccountNo();
+        BalAccountNo := LibraryERM.CreateGLAccountNo();
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo1);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo2);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo3);
+        AutomaticAccountLine.Validate("Allocation %", -100);
+        AutomaticAccountLine.Modify(true);
+
+        // [GIVEN] Amount in FCY = 480 which converts to 5266.67 LCY
+        // [GIVEN] 5266.67 / 2 = 2633.335, rounds to 2633.34
+        // [GIVEN] 2633.34 + 2633.34 = 5266.68 <> 5266.67 (rounding discrepancy)
+        AmountFCY := 480;
+        ExpectedAmountLCY := Round(AmountFCY * CurrencyExchangeRate."Relational Exch. Rate Amount", GLSetup."Amount Rounding Precision");
+
+        // [GIVEN] General Journal with Currency and two lines:
+        // [GIVEN] Line1: Amount = 480 EUR, "Automatic Account Group" = "AAG", "Bal. Account No." = ''
+        // [GIVEN] Line2: Amount = -480 EUR, "Automatic Account Group" = '', "Bal. Account No." = '' (balancing)
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, LibraryERM.SelectGenJnlTemplate());
+
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountNo(), AmountFCY);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Validate("Automatic Account Group", AutoAccGroupNo);
+        GenJournalLine.Validate("Bal. Account No.", '');
+        GenJournalLine.Modify(true);
+        DocumentNo := GenJournalLine."Document No.";
+
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account",
+            BalAccountNo, -AmountFCY);
+        GenJournalLine.Validate("Document No.", DocumentNo);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Modify(true);
+
+        // [WHEN] Post General Journal
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] G/L Entries are created without inconsistency error
+        // [THEN] The sum of all G/L Entry amounts for the document equals zero
+        GLEntry.SetRange("Document No.", DocumentNo);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'Total G/L Entry balance should be zero');
+
+        // [THEN] Auto Acc. Group entries sum to zero (proper rounding adjustment applied)
+        GLEntry.SetFilter("G/L Account No.", '%1|%2|%3', GLAccountNo1, GLAccountNo2, GLAccountNo3);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'Auto Acc. Group G/L Entry balance should be zero');
+    end;
 }

