+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    procedure ProdOrderCompQtyPerNotZeroWithHighQtyRoundPrecisionOnComponentUOM()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ItemUOM: Record "Item Unit of Measure";
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Production BOM] [Quantity Rounding Precision]
+        // [SCENARIO] When a component's Item UOM has 'Qty. Rounding Precision' of 1, and a finished good consumes partial quantity,
+        // the Prod. Order created from Sales Order should have correct 'Qty. Per' and 'Expected Qty.', not 0.
+        Initialize();
+
+        // [GIVEN] A component item with base UoM having 'Qty. Rounding Precision' = 1
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Validate("Reordering Policy", ComponentItem."Reordering Policy"::"Lot-for-Lot");
+        ComponentItem.Modify(true);
+        ItemUOM.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUOM."Qty. Rounding Precision" := 1;
+        ItemUOM.Modify(true);
+
+        // [GIVEN] A finished good item with Production BOM consuming component with 'Quantity Per' = 0.09
+        QtyPer := 0.09;
+        LibraryInventory.CreateItem(FinishedGoodItem);
+        FinishedGoodItem.Validate("Replenishment System", FinishedGoodItem."Replenishment System"::"Prod. Order");
+        FinishedGoodItem.Validate("Rounding Precision", 1);
+        FinishedGoodItem.Validate("Reordering Policy", FinishedGoodItem."Reordering Policy"::Order);
+        FinishedGoodItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FinishedGoodItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        FinishedGoodItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodItem.Modify(true);
+
+        // [GIVEN] A sales order for the finished good item with quantity 1
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, FinishedGoodItem."No.", 1);
+
+        // [WHEN] Create a Released Production Order from the Sales Order
+        LibraryVariableStorage.Enqueue(ReleasedProductionOrderCreatedTxt);
+        LibraryManufacturing.CreateProductionOrderFromSalesOrder(
+            SalesHeader, ProductionOrder.Status::Released, "Create Production Order Type"::ItemOrder);
+
+        // [THEN] The Prod. Order Component has correct 'Quantity per' and 'Expected Quantity', not 0
+        ProductionOrder.SetRange("Source No.", FinishedGoodItem."No.");
+        ProductionOrder.SetRange(Status, ProductionOrder.Status::Released);
+        ProductionOrder.FindFirst();
+
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        Assert.AreEqual(
+            QtyPer, ProdOrderComponent."Quantity per",
+            'Quantity per should be preserved and not rounded to 0');
+        Assert.AreEqual(
+            QtyPer, ProdOrderComponent."Expected Quantity",
+            'Expected Quantity should be preserved and not rounded to 0');
+    end;
