+    procedure VerifyDueDateInReminderFinChargeEntryAfterUpdateToEarlierDueDate()
+    var
+        Customer: Record Customer;
+        ReminderLevel: Record "Reminder Level";
+        ReminderFinChargeEntry: Record "Reminder/Fin. Charge Entry";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        DueDate: Date;
+        DocumentDate: Date;
+        EarlierDueDate: Date;
+        IssuedReminderNo: Code[20];
+    begin
+        // [SCENARIO] The Due Date in the Reminder/Fin. Charge Entry is updated when changing the Due Date in the Customer Ledger Entry to an earlier date.
