+        // [GIVEN] Create a component item with routing (for capacity cost).
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Replenishment System", CompItem."Replenishment System"::"Prod. Order");
+        CompItem.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 50, 2));
+        CompItem.Modify(true);
+
+        // [GIVEN] Create a routing with a work center for the component.
+        LibraryManufacturing.CreateWorkCenter(WorkCenter);
+        WorkCenter.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(10, 30, 2));
+        WorkCenter.Modify(true);
+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
+        LibraryManufacturing.CreateRoutingLine(
+          RoutingHeader, RoutingLine, '', Format(1), RoutingLine.Type::"Work Center", WorkCenter."No.");
+        RoutingLine.Validate("Run Time", LibraryRandom.RandIntInRange(5, 10));
+        RoutingLine.Modify(true);
+        LibraryManufacturing.UpdateRoutingStatus(RoutingHeader, RoutingHeader.Status::Certified);
+
+        // [GIVEN] Assign the routing to the component item.
+        CompItem.Find();
+        CompItem.Validate("Routing No.", RoutingHeader."No.");
+        CompItem.Modify(true);
+
+        // [GIVEN] Create a parent item with Production BOM containing the component.
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        ParentItem.Find();
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create an empty (blank) Production BOM for the component.
+        LibraryManufacturing.CreateProductionBOMHeader(BlankProductionBOMHeader, CompItem."Base Unit of Measure");
+        LibraryManufacturing.UpdateProductionBOMStatus(BlankProductionBOMHeader, BlankProductionBOMHeader.Status::Certified);
+
+        // [WHEN] Assign the blank BOM to the component item and open BOM Cost Shares page.
+        CompItem.Find();
+        CompItem.Validate("Production BOM No.", BlankProductionBOMHeader."No.");
+        CompItem.Modify(true);
+
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ParentItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        RolledUpCapCostWithBlankBom := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [WHEN] Remove the Production BOM from the component item and open BOM Cost Shares page again.
+        CompItem.Find();
+        CompItem.Validate("Production BOM No.", '');
+        CompItem.Modify(true);
+
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ParentItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        RolledUpCapCostWithNoBom := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [THEN] The Rolled-up Capacity Cost should be the same in both cases.
+        Assert.AreEqual(
+          RolledUpCapCostWithNoBom, RolledUpCapCostWithBlankBom,
+          'Rolled-up Capacity Cost should be the same for blank BOM and no BOM.');
+    end;
 }

