+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure UndoTransferShipmentAfterRevaluationValuesEntry()
+    var
+        Item: Record Item;
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        InTransitLocation: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalTemplate: Record "Item Journal Template";
+        OriginalUnitCost: Decimal;
+        RevaluedUnitCost: Decimal;
+        Qty: Decimal;
+        TotalCostAmount: Decimal;
+    begin
+        // [FEATURE] [Transfer] [Order] [Undo Shipment] [Revaluation]
+        // [SCENARIO] When a transfer shipment is undone after the original inbound entry was revalued, the undo entries should use the revalued cost
+        Initialize();
+
+        // [GIVEN] Create an item and two locations
+        LibraryInventory.CreateItem(Item);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        // [GIVEN] Post positive adjustment with known unit cost = 10
+        Qty := 1;
+        OriginalUnitCost := 10;
+        RevaluedUnitCost := 12;
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", Qty);
+        ItemJournalLine.Validate("Location Code", FromLocation.Code);
+        ItemJournalLine.Validate("Unit Cost", OriginalUnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+
+        // [GIVEN] Find the positive adjustment item ledger entry
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create and ship transfer order from FromLocation to ToLocation
+        LibraryInventory.CreateTransferHeader(TransferHeader, FromLocation.Code, ToLocation.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Qty);
+        LibraryInventory.PostTransferHeader(TransferHeader, true, false);
+
+        // [GIVEN] Create revaluation journal to revalue the original positive adjustment entry to new cost = 12
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Revaluation);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Revaluation, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::Transfer, Item."No.", 0);
+        ItemJournalLine.Validate("Value Entry Type", ItemJournalLine."Value Entry Type"::Revaluation);
+        ItemJournalLine.Validate("Applies-to Entry", ItemLedgerEntry."Entry No.");
+        ItemJournalLine.Validate("Unit Cost (Revalued)", RevaluedUnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+
+        // [GIVEN] Run Adjust Cost - Item Entries
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [WHEN] Undo the posted transfer shipment
+        LibraryInventory.UndoTransferShipments(TransferHeader."No.");
+
+        // [WHEN] Run Adjust Cost - Item Entries again
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [THEN] The total cost amount for all item ledger entries should be zero 
+        // (inventory is back at origin with correct cost)
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        TotalCostAmount := 0;
+        if ItemLedgerEntry.FindSet() then
+            repeat
+                ItemLedgerEntry.CalcFields("Cost Amount (Actual)");
+                TotalCostAmount += ItemLedgerEntry."Cost Amount (Actual)";
+            until ItemLedgerEntry.Next() = 0;
+
+        // Total cost should be the revalued cost (12) for 1 item at From Location
+        // The transfer should net to zero cost (outbound -12, undo shipment +12)
+        Assert.AreEqual(RevaluedUnitCost * Qty, TotalCostAmount, 'Total cost amount should equal revalued cost for remaining inventory');
+
+        // [THEN] Verify the positive undo transfer entry uses the revalued cost, not the original cost
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Transfer);
+        ItemLedgerEntry.SetRange("Location Code", FromLocation.Code);
+        ItemLedgerEntry.SetRange(Positive, true);
+        ItemLedgerEntry.SetFilter("Document Type", '%1', ItemLedgerEntry."Document Type"::"Transfer Shipment");
+        ItemLedgerEntry.FindLast();
+        ItemLedgerEntry.CalcFields("Cost Amount (Actual)");
+        Assert.AreEqual(RevaluedUnitCost * Qty, ItemLedgerEntry."Cost Amount (Actual)",
+            'Undo transfer shipment entry should have revalued cost, not original cost');
+    end;
 }

