+    [Test]
+    [Scope('OnPrem')]
+    procedure RoundingIssuesWithTrackingStatusEntriesSplitIntoThree()
+    var
+        ReservationEntry: Record "Reservation Entry";
+        ReservationEntry2: Record "Reservation Entry";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        Item: Record Item;
+        UOMMgt: Codeunit "Unit of Measure Management";
+        TotalQuantity: Decimal;
+        QtyPerUOM: Decimal;
+        TotalQtyBase: Decimal;
+        Qty1Base: Decimal;
+        Qty2Base: Decimal;
+        Qty3Base: Decimal;
+        SourceID: Code[20];
+        SourceRefNo: Integer;
+        ExpectedTotalQty: Decimal;
+    begin
+        // [SCENARIO] When tracking entries are split into 3 parts with quantities ending in repeating decimals,
+        // the CalcReservationQuantity function should correctly sum the quantities without rounding errors.
+        // [GIVEN] A Sales Order with UOM conversion that causes repeating decimals when split into 3 entries.
+        // Setup: Use Qty per UOM = 24 (CASE of 24 pcs), Total = 12 CASES = 288 pcs base.
+        // Split into 3 parts: each ~96 pcs base = 4 CASES, but with specific values that cause rounding.
+        Initialize();
+
+        // Create Item with CASE UOM = 24 per base (simulating the repro scenario)
+        QtyPerUOM := 24;
+        ExpectedTotalQty := 12;
+        TotalQtyBase := 288; // 12 CASES * 24 = 288 pcs
+
+        // Create quantities that when divided by 24 end in repeating decimals
+        // Using 13 + 220 + 55 = 288 as in the repro (13 pcs, then 220 pcs split, then remaining)
+        // 13/24 = 0.54167, 220/24 = 9.16667, 55/24 = 2.29167
+        // Sum: 0.54167 + 9.16667 + 2.29167 = 12.00001 (the bug)
+        // With the fix, each entry's Quantity is calculated considering all tracking entries
+        Qty1Base := 13;
+        Qty2Base := 220;
+        Qty3Base := 55;
+
+        // Create Item
+        Item."No." := LibraryUtility.GenerateRandomCode(Item.FieldNo("No."), DATABASE::Item);
+        Item.Insert();
+
+        // Create Item Unit of Measure
+        ItemUnitOfMeasure."Item No." := Item."No.";
+        ItemUnitOfMeasure.Code := 'CA';
+        ItemUnitOfMeasure."Qty. per Unit of Measure" := QtyPerUOM;
+        ItemUnitOfMeasure.Insert();
+
+        // Create a Sales Order to use as source
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLineSimple(SalesLine, SalesHeader);
+        SalesLine."No." := Item."No.";
+        SalesLine.Quantity := ExpectedTotalQty;
+        SalesLine."Quantity (Base)" := TotalQtyBase;
+        SalesLine."Unit of Measure Code" := ItemUnitOfMeasure.Code;
+        SalesLine."Qty. per Unit of Measure" := QtyPerUOM;
+        SalesLine.Modify();
+
+        SourceID := SalesHeader."No.";
+        SourceRefNo := SalesLine."Line No.";
+
+        // [GIVEN] Three reservation entries with Tracking status for the same source
+        // Entry 1
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := 1;
+        ReservationEntry."Item No." := Item."No.";
+        ReservationEntry."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry.Positive := false;
+        ReservationEntry."Quantity (Base)" := -Qty1Base;
+        ReservationEntry.Quantity := -Round(Qty1Base / QtyPerUOM, UOMMgt.QtyRndPrecision());
+        ReservationEntry.Insert();
+
+        // Entry 2
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := 2;
+        ReservationEntry."Item No." := Item."No.";
+        ReservationEntry."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry."Source Subtype" := 1;
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry.Positive := false;
+        ReservationEntry."Quantity (Base)" := -Qty2Base;
+        ReservationEntry.Quantity := -Round(Qty2Base / QtyPerUOM, UOMMgt.QtyRndPrecision());
+        ReservationEntry.Insert();
+
+        // Entry 3
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := 3;
+        ReservationEntry."Item No." := Item."No.";
+        ReservationEntry."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry."Source Subtype" := 1;
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry.Positive := false;
+        ReservationEntry."Quantity (Base)" := -Qty3Base;
+        ReservationEntry.Quantity := -Round(Qty3Base / QtyPerUOM, UOMMgt.QtyRndPrecision());
+        ReservationEntry.Insert();
+
+        // [WHEN] We validate the Quantity (Base) on the third entry to trigger CalcReservationQuantity
+        ReservationEntry.Get(3, false);
+        ReservationEntry.Validate("Quantity (Base)", -Qty3Base);
+        ReservationEntry.Modify();
+
+        // Now recalculate all entries to trigger CalcReservationQuantity for each
+        ReservationEntry.Get(1, false);
+        ReservationEntry.Validate("Quantity (Base)", -Qty1Base);
+        ReservationEntry.Modify();
+
+        ReservationEntry.Get(2, false);
+        ReservationEntry.Validate("Quantity (Base)", -Qty2Base);
+        ReservationEntry.Modify();
+
+        // [THEN] The sum of all Quantity values should equal the expected total (12 CASES) without rounding error
+        ReservationEntry2.SetRange("Source Type", DATABASE::"Sales Line");
+        ReservationEntry2.SetRange("Source ID", SourceID);
+        ReservationEntry2.SetRange("Source Ref. No.", SourceRefNo);
+        ReservationEntry2.CalcSums(Quantity);
+        TotalQuantity := -ReservationEntry2.Quantity;
+
+        Assert.AreEqual(ExpectedTotalQty, TotalQuantity,
+            'Sum of Quantity in tracking entries should equal expected total without rounding error (12.00001 bug)');
+    end;
+
     local procedure RoundingIssuesRunScenario(SupplySourceType: Option; DemandSourceType: Option)
     begin
         RoundingIssuesScenario(false, false, SupplySourceType, DemandSourceType);

