+    [Test]
+    [HandlerFunctions('ItemTrackingLinesLotAssignPageHandler')]
+    [Scope('OnPrem')]
+    procedure RecalcPlanWithItemTrackingAndPlanningFlexibilityNoneShouldNotCreateWrongSurplusEntries()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        PurchaseLine: Record "Purchase Line";
+        ReservationEntry: Record "Reservation Entry";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        SalesQty: Decimal;
+        ExtraQty: Decimal;
+        TotalPurchQty: Decimal;
+        InitialSurplusCount: Integer;
+        FinalSurplusCount: Integer;
+    begin
+        // [FEATURE] [Requisition Worksheet] [Item Tracking] [Planning Flexibility]
+        // [SCENARIO] Recalculating an item in requisition worksheet with Planning Flexibility = None and item tracking
+        // should not create wrong surplus entries in the reservation table.
+        // Bug: After recalculating item in requisition worksheet when no planning results exist (due to Planning Flexibility = None),
+        // wrong surplus entries are created for the added quantity (difference between purchase qty and sales demand).
+
+        Initialize();
+
+        // [GIVEN] Create Lot-for-Lot Item with Lot tracking
+        CreateLotForLotItem(Item, 0, '<0D>');
+        LibraryItemTracking.AddLotNoTrackingInfo(Item);
+
+        // [GIVEN] Create a Sales Order
+        SalesQty := LibraryRandom.RandIntInRange(50, 100);
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", SalesQty);
+
+        // [GIVEN] Calculate Plan for Requisition Worksheet
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Modify the requisition line: increase quantity by extra amount, set Planning Flexibility to None, set Vendor
+        ExtraQty := LibraryRandom.RandIntInRange(20, 50);
+        TotalPurchQty := SalesQty + ExtraQty;
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Validate(Quantity, TotalPurchQty);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot tracking on the requisition line
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Accept action message and Carry out action message to create Purchase Order
+        AcceptActionMessage(Item."No.");
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Verify Purchase Order is created with correct quantity
+        SelectPurchaseLine(PurchaseLine, Item."No.");
+        PurchaseLine.TestField(Quantity, TotalPurchQty);
+
+        // [GIVEN] Count initial surplus reservation entries for the Purchase Line
+        ReservationEntry.SetSourceFilter(Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.", PurchaseLine."Line No.", true);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        InitialSurplusCount := ReservationEntry.Count();
+
+        // [WHEN] Calculate Plan again for Requisition Worksheet (no planning results due to Planning Flexibility = None)
+        RequisitionWkshName.FindFirst();
+        LibraryPlanning.CalculatePlanForReqWksh(
+          Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [THEN] No requisition line should be created (due to Planning Flexibility = None)
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty, StrSubstNo(RequisitionLineMustNotExistTxt, Item."No."));
+
+        // [THEN] No new surplus entries should be created for the Purchase Line
+        ReservationEntry.SetSourceFilter(Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.", PurchaseLine."Line No.", true);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        FinalSurplusCount := ReservationEntry.Count();
+
+        Assert.AreEqual(InitialSurplusCount, FinalSurplusCount, 'Surplus reservation entry count should not change after recalculating the plan');
+
+        // [THEN] There should be no Prospect entries for the Purchase Line (they should have been converted to Surplus)
+        ReservationEntry.SetSourceFilter(Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.", PurchaseLine."Line No.", true);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+        Assert.RecordIsEmpty(ReservationEntry);
+    end;
+
