+    [Test]
+    [Scope('OnPrem')]
+    procedure CustomerTotalAmountNotTripledWhenInvoiceUsesGetShipmentLines()
+    var
+        Customer: Record Customer;
+        SalesLine: Record "Sales Line";
+        SalesShipmentLine: Record "Sales Shipment Line";
+        OrderNo: Code[20];
+        InvoiceNo: Code[20];
+        ShipmentNo: Code[20];
+        OrderLineNo: Integer;
+        InvoiceLineNo: Integer;
+        ShipmentLineNo: Integer;
+        ShippedNotInvoicedAmount: Decimal;
+        ExpectedTotalAmount: Decimal;
+    begin
+        // [SCENARIO] Customer Card Statistics Total Amount should not triple-count when Sales Invoice uses Get Shipment Lines
+        // When a Sales Order is shipped and a Sales Invoice uses Get Shipment Lines, the amount should be counted only once
+        Initialize();
+
+        // [GIVEN] A customer
+        LibrarySales.CreateCustomer(Customer);
+        OrderNo := LibraryUtility.GenerateRandomCode(SalesLine.FieldNo("Document No."), DATABASE::"Sales Line");
+        InvoiceNo := LibraryUtility.GenerateRandomCode(SalesLine.FieldNo("Document No."), DATABASE::"Sales Line");
+        ShipmentNo := LibraryUtility.GenerateRandomCode(SalesShipmentLine.FieldNo("Document No."), DATABASE::"Sales Shipment Line");
+        OrderLineNo := 10000;
+        InvoiceLineNo := 10000;
+        ShipmentLineNo := 10000;
+        ShippedNotInvoicedAmount := LibraryRandom.RandDecInRange(1000, 10000, 2);
+        ExpectedTotalAmount := ShippedNotInvoicedAmount;
+
+        // [GIVEN] A Sales Order Line with Shipped Not Invoiced amount (simulating a shipped order)
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesLine."Document Type"::Order;
+        SalesLine."Document No." := OrderNo;
+        SalesLine."Line No." := OrderLineNo;
+        SalesLine."Bill-to Customer No." := Customer."No.";
+        SalesLine."Shipped Not Invoiced (LCY)" := ShippedNotInvoicedAmount;
+        SalesLine.Insert();
+
+        // [GIVEN] A Sales Shipment Line linked to the Order (created when the order was shipped)
+        SalesShipmentLine.Init();
+        SalesShipmentLine."Document No." := ShipmentNo;
+        SalesShipmentLine."Line No." := ShipmentLineNo;
+        SalesShipmentLine."Bill-to Customer No." := Customer."No.";
+        SalesShipmentLine."Order No." := OrderNo;
+        SalesShipmentLine."Order Line No." := OrderLineNo;
+        SalesShipmentLine.Insert();
+
+        // [GIVEN] A Sales Invoice Line created via Get Shipment Lines (linked to the shipment)
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesLine."Document Type"::Invoice;
+        SalesLine."Document No." := InvoiceNo;
+        SalesLine."Line No." := InvoiceLineNo;
+        SalesLine."Bill-to Customer No." := Customer."No.";
+        SalesLine."Sell-to Customer No." := Customer."No.";
+        SalesLine."Outstanding Amount (LCY)" := ShippedNotInvoicedAmount;
+        SalesLine."Shipment No." := ShipmentNo;
+        SalesLine."Shipment Line No." := ShipmentLineNo;
+        SalesLine.Insert();
+
+        // [WHEN] Customer's Total Amount is calculated
+        // [THEN] Total Amount equals the single shipment amount, not tripled
+        // Without the fix, this would be ShippedNotInvoicedAmount * 3 because:
+        // 1. "Shipped Not Invoiced (LCY)" from order = ShippedNotInvoicedAmount
+        // 2. "Outstanding Invoices (LCY)" from invoice = ShippedNotInvoicedAmount  
+        // 3. SalesOutstandingAmountFromShipment = ShippedNotInvoicedAmount
+        // With the fix, duplicates are subtracted so the total equals the expected single amount
+        Assert.AreEqual(ExpectedTotalAmount, Customer.GetTotalAmountLCY(), 'Total Amount should not be tripled when Sales Invoice uses Get Shipment Lines');
+    end;
+
