+        ItemLedgerEntry: Record "Item Ledger Entry";
+        Location: array[3] of Record Location;
+        PurchaseReceiptNo: Code[20];
+    begin
+        // [FEATURE] [Get Receipt Lines] [Appl.-to Item Entry] [Location]
+        // [SCENARIO] "Get Receipt Lines" shows purchase receipts with location only on lines and sets Appl.-to Item Entry
+        // Bug: When purchase order header has no location but line has location, receipt was not shown.
+        // Bug: Appl.-to Item Entry was not set when creating transfer lines from receipt lines.
+        Initialize();
+
+        // [GIVEN] Item "ITEM1" with costing method FIFO
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Modify(true);
+
+        // [GIVEN] Locations "LOC1" (transfer from), "LOC2" (transfer to), and "LOC3" (in transit)
+        LibraryWarehouse.CreateTransferLocations(Location[1], Location[2], Location[3]);
+
+        // [GIVEN] Post purchase order with location only on line (not on header) to "LOC1"
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, LibraryPurchase.CreateVendorNo());
+        // Header location is blank - only line has location
+        LibraryPurchase.CreatePurchaseLine(
+          PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(5, 10));
+        PurchaseLine.Validate("Location Code", Location[1].Code);
+        PurchaseLine.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(100, 200, 2));
+        PurchaseLine.Modify(true);
+        PurchaseReceiptNo := LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // [GIVEN] Get the posted receipt line and related Item Ledger Entry
+        PurchRcptLine.SetRange("Document No.", PurchaseReceiptNo);
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.FindFirst();
+
+        ItemLedgerEntry.SetRange("Document No.", PurchaseReceiptNo);
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create transfer order from location "LOC1" to "LOC2"
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, Location[1].Code, Location[2].Code, Location[3].Code);
+
+        // [WHEN] Run function "Get Receipt Lines" selecting the purchase receipt and its line
+        LibraryVariableStorage.Enqueue(PurchaseReceiptNo); // Purchase Receipt to select
+        LibraryVariableStorage.Enqueue(Item."No."); // Purchase Receipt Line to select by Item No.
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created with the correct item and Appl.-to Item Entry is set to the Item Ledger Entry
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        TransferLine.SetRange("Item No.", Item."No.");
+        TransferLine.FindFirst();
+        TransferLine.TestField("Item No.", Item."No.");
+        TransferLine.TestField(Quantity, PurchRcptLine.Quantity);
+        TransferLine.TestField("Appl.-to Item Entry", ItemLedgerEntry."Entry No.");
+    end;
+
     [Test]
     [HandlerFunctions('ItemChargeAssignmentPurchModalPageHandler,PostedTransferReceiptLinesModalPageHandler')]
     [Scope('OnPrem')]

